const data: Record<string, Category> = {
    "HTML / CSS / Browser": {
        icon: "🌐",
        color: "#e8703a",
        questions: [
            { level: "junior", q: "Що таке семантичний HTML? Навіщо він потрібен?", a: "Семантичний HTML — це використання тегів за їх призначенням: <header>, <nav>, <main>, <article>, <section>, <aside>, <footer> замість універсальних <div>. Переваги: 1) Accessibility — скрінрідери розуміють структуру сторінки. 2) SEO — пошукові роботи краще індексують контент. 3) Читабельність коду — розробники одразу бачать структуру. 4) Підтримуваність — легше підтримувати та рефакторити." },
            { level: "junior", q: "Яка різниця між `display: none`, `visibility: hidden` і `opacity: 0`?", a: "`display: none` — повністю прибирає елемент з DOM flow, не займає місце, не реагує на події. `visibility: hidden` — елемент невидимий, але займає місце в layout, не реагує на події. `opacity: 0` — елемент прозорий, займає місце, РЕАГУЄ на події (click, hover). Також: display: none не анімується, opacity — можна анімувати, visibility — можна анімувати тільки з delay." },
            { level: "junior", q: "Поясни Box Model. Яка різниця між `box-sizing: content-box` і `border-box`?", a: "Box Model складається з: content → padding → border → margin. `content-box` (default): width/height задає тільки content. Padding і border додаються поверх. Елемент з width: 100px + padding: 10px + border: 1px = 122px. `border-box`: width/height включає content + padding + border. Елемент з width: 100px завжди буде 100px, content зменшується. Рекомендовано: *, *::before, *::after { box-sizing: border-box; }" },
            { level: "junior", q: "Що таке специфічність у CSS? Як вона обчислюється?", a: "Специфічність визначає, який CSS-правило переможе при конфлікті. Обчислюється як (a, b, c): a — кількість id-селекторів (#id = 1,0,0). b — кількість класів, атрибутів, псевдокласів (.class = 0,1,0). c — кількість елементів, псевдоелементів (div = 0,0,1). Inline styles (style=\"\") мають найвищий пріоритет. !important перемагає все (але це антипатерн). Універсальний * та комбінатори (+, >, ~) мають 0 специфічність." },
            { level: "junior", q: "Яка різниця між `position: relative`, `absolute`, `fixed`, `sticky`?", a: "`relative` — елемент зміщується відносно свого нормального положення, але продовжує займати місце в потоці. `absolute` — вилучається з потоку, позиціонується відносно найближчого positioned ancestor (або viewport). `fixed` — вилучається з потоку, позиціонується відносно viewport, не скролиться. `sticky` — гібрид: поводить себе як relative, поки не досягне вказаного offset при скролі, тоді стає fixed. Працює тільки всередині свого scroll-контейнера." },
            { level: "junior", q: "Що таке Flexbox? Поясни основні властивості.", a: "Flexbox — одновимірна система layout (рядок АБО колонка). Контейнер: display: flex, flex-direction (row/column), justify-content (вирівнювання по головній осі: flex-start, center, space-between, space-around, space-evenly), align-items (по перпендикулярній осі: stretch, center, flex-start, flex-end), flex-wrap (перенесення на новий рядок), gap (відстань між елементами). Елементи: flex-grow (розтягування), flex-shrink (стискання), flex-basis (базовий розмір), order (порядок), align-self (індивідуальне вирівнювання)." },
            { level: "junior", q: "Що таке CSS Grid? Чим відрізняється від Flexbox?", a: "CSS Grid — двовимірна система layout (рядки І колонки одночасно). Ключові відмінності: Flexbox — одновимірний (рядок або колонка), Grid — двовимірний. Flexbox — content-first (розмір залежить від контенту), Grid — layout-first (контент підлаштовується під сітку). Властивості Grid: grid-template-columns/rows, grid-template-areas, grid-gap, grid-column/row (span), fr unit, repeat(), minmax(), auto-fill/auto-fit. Коли що: Flexbox — навбари, кнопки, прості ряди. Grid — складні макети сторінок, dashboards, галереї." },
            { level: "junior", q: "Що таке медіа-запити? Як зробити responsive дизайн?", a: "Медіа-запити (@media) дозволяють застосовувати CSS залежно від характеристик пристрою: ширина (min-width, max-width), орієнтація, роздільна здатність, prefers-color-scheme, prefers-reduced-motion. Підходи: Mobile-first (min-width) — рекомендований, Desktop-first (max-width). Breakpoints: 480px (mobile), 768px (tablet), 1024px (desktop), 1200px+ (large). Також: використовувати відносні одиниці (rem, em, %), viewport units (vw, vh), clamp() для fluid typography." },
            { level: "middle", q: "Поясни CSS Custom Properties (змінні). Яка їх перевага над SCSS змінними?", a: "CSS Custom Properties (--name: value) працюють в runtime, а SCSS змінні ($name) компілюються при збірці. Переваги CSS змінних: 1) Каскадність — можна перевизначити для нащадків. 2) Динамічність — змінюються через JS (element.style.setProperty) і медіа-запити. 3) Theming — легко перемикати теми без ребілду. 4) Не потребують препроцесора. Недоліки: немає функцій/міксинів як у SCSS. Приклад: :root { --primary: #58a6ff; } .btn { color: var(--primary, fallback); }" },
            { level: "middle", q: "Що таке CSS-in-JS? Які переваги та недоліки?", a: "CSS-in-JS — підхід написання стилів у JS-файлах (styled-components, Emotion, vanilla-extract). Переваги: 1) Scoping — стилі ізольовані до компонента, немає колізій імен. 2) Динамічні стилі через props/state. 3) Dead code elimination — невикористані стилі видаляються. 4) Colocation — стилі поруч з компонентом. Недоліки: 1) Runtime overhead — генерація стилів у рантаймі (крім zero-runtime: vanilla-extract, Linaria). 2) Збільшення bundle size. 3) Ускладнення серверного рендерингу. 4) Ускладнення кешування стилів." },
            { level: "middle", q: "Як працює CSS cascade та inheritance?", a: "Cascade визначає порядок застосування стилів (від найнижчого до найвищого пріоритету): 1) User agent styles (дефолтні стилі браузера). 2) User styles. 3) Author styles. 4) Author !important. 5) User !important. Всередині одного рівня: специфічність → порядок у коді. CSS Layers (@layer) дозволяють контролювати порядок каскаду. Inheritance: деякі властивості наслідуються (color, font-*, line-height, text-*), інші ні (margin, padding, border, display). inherit/initial/unset/revert — ключові слова для контролю." },
            { level: "middle", q: "Що таке BEM? Навіщо він потрібен?", a: "BEM (Block, Element, Modifier) — методологія іменування CSS-класів. Block — незалежний компонент (.card). Element — частина блоку (.card__title, .card__image). Modifier — варіація (.card--featured, .card__title--large). Навіщо: 1) Уникнення конфліктів імен. 2) Зрозуміла структура — одразу видно зв'язки між класами. 3) Низька специфічність — всі селектори одного рівня. 4) Reusability — блоки незалежні. Обмеження: довгі імена класів, не вирішує все (тому часто доповнюють CSS Modules або CSS-in-JS)." },
            { level: "middle", q: "Поясни стacking context. Як він створюється?", a: "Stacking context — контекст, який визначає порядок відображення елементів по осі Z. Всередині контексту z-index працює ізольовано. Створюється: 1) Кореневий елемент <html>. 2) position: relative/absolute/fixed/sticky + z-index (не auto). 3) opacity < 1. 4) transform, filter, perspective (будь-яке значення). 5) will-change: transform/opacity. 6) isolation: isolate. 7) mix-blend-mode (не normal). Порядок без z-index: background → negative z-index → block → float → inline → z-index: 0 → positive z-index." },
            { level: "middle", q: "Що таке critical CSS? Як його оптимізувати?", a: "Critical CSS — мінімальний набір стилів, потрібний для рендерингу above-the-fold контенту (те, що видно без прокрутки). Оптимізація: 1) Інлайнити critical CSS у <style> в <head>. 2) Решту CSS завантажувати async через <link rel='preload' as='style'>. 3) Інструменти: critical, penthouse, critters (webpack plugin). Це покращує FCP (First Contentful Paint) і LCP, бо браузер не чекає завантаження повного CSS-файлу для першого рендеру. Next.js та інші фреймворки автоматизують це." },
            { level: "middle", q: "Як браузер парсить та рендерить HTML/CSS? Поясни CRP (Critical Rendering Path).", a: "CRP: 1) Parsing HTML → DOM tree. 2) Parsing CSS → CSSOM tree. 3) DOM + CSSOM → Render tree (тільки видимі елементи). 4) Layout (Reflow) — обчислення розмірів і позицій. 5) Paint — малювання пікселів (кольори, тіні, текст). 6) Composite — об'єднання шарів. CSS блокує рендеринг (render-blocking). JS блокує парсинг HTML (parser-blocking), якщо без async/defer. Оптимізація: мінімізувати CSS, defer/async для JS, lazy loading, preload критичних ресурсів." },
            { level: "middle", q: "Що таке reflow та repaint? Як їх уникнути?", a: "Repaint — перемальовування елемента без зміни layout (зміна color, background, visibility). Reflow (Layout) — перерахунок позицій і розмірів елементів (зміна width, height, padding, margin, position, font-size, додавання/видалення елементів). Reflow дорожчий і завжди викликає repaint. Як уникнути: 1) Batch DOM зміни (documentFragment, display:none → зміни → display:block). 2) Використовувати transform/opacity замість top/left/width. 3) Уникати читання layout properties (offsetWidth) між записами. 4) will-change для анімованих елементів. 5) CSS containment." },
            { level: "senior", q: "Що таке CSS containment? Як `contain: layout paint` впливає на перформанс?", a: "CSS containment (contain) повідомляє браузеру, що елемент ізольований від решти сторінки. Значення: `layout` — layout елемента не впливає на зовнішні елементи і навпаки. `paint` — контент не малюється за межами елемента (як overflow: hidden для рендерингу). `size` — розмір елемента не залежить від нащадків. `style` — лічильники та quotes ізольовані. `contain: layout paint` дозволяє браузеру: 1) Пропускати layout/paint для off-screen елементів. 2) Обмежити reflow тільки цим піддеревом. content-visibility: auto — автоматична containment для невидимих елементів, значно прискорює рендеринг довгих списків." },
            { level: "senior", q: "Поясни Layer promotion у браузері. Коли і навіщо використовувати `will-change`?", a: "Браузер може виділити елемент в окремий compositing layer (GPU layer). Це дозволяє анімувати його незалежно без reflow/repaint решти сторінки. Promotion відбувається при: transform, opacity анімації, will-change, position: fixed, <video>/<canvas>. `will-change` підказує браузеру заздалегідь створити layer: will-change: transform, opacity. Коли використовувати: тільки для елементів, які дійсно будуть анімуватися. Проблеми надмірного використання: 1) Кожен layer займає GPU пам'ять. 2) Занадто багато layers — layer explosion — може сповільнити композитинг. 3) Додавати перед анімацією, прибирати після." },
            { level: "senior", q: "Що таке CSS Houdini? Які API він надає?", a: "CSS Houdini — набір low-level API, які дають JS-доступ до CSS engine браузера. API: 1) Paint API (CSS.paintWorklet) — кастомний paint для background-image. 2) Layout API — кастомний layout алгоритм (display: layout(my-layout)). 3) Animation Worklet — анімації в окремому потоці (не блокують main thread). 4) Properties and Values API (CSS.registerProperty) — типізовані кастомні властивості з інтерполяцією. 5) Typed OM — доступ до CSS значень як об'єктів (не рядків). 6) Parser API — доступ до CSS парсера. Підтримка: Paint API та Properties API підтримуються в Chromium, решта — експериментальні." },
            { level: "senior", q: "Як ти організовуєш CSS архітектуру у великому проєкті?", a: "Підхід залежить від проєкту: 1) CSS Modules — scoped класи, файл стилів поруч з компонентом (.module.css). 2) Tailwind CSS — utility-first, швидка розробка, design system з коробки. 3) styled-components/Emotion — CSS-in-JS, динамічні стилі. 4) vanilla-extract — zero-runtime CSS-in-TS. Загальні принципи: Design Tokens (кольори, spacing, typography як змінні). Компонентний підхід — стилі колоковані з компонентами. Консистентність — один підхід на проєкт. Theming — CSS Custom Properties для тем. Responsive — mobile-first, design system breakpoints. Лінтинг — stylelint для консистентності." },
            { level: "senior", q: "Поясни різницю між hardware-accelerated compositing і software rendering.", a: "Software rendering: CPU малює всі пікселі. Весь layout, paint, compositing відбувається на CPU. Простіший, менше пам'яті, але повільніший для складних сцен і анімацій. Hardware-accelerated compositing: елементи виділяються в окремі GPU layers (текстури). GPU виконує compositing (з'єднання шарів), трансформації, opacity. CPU все ще відповідає за layout і paint, але GPU паралельно обробляє композитинг. Переваги GPU: паралелізм (тисячі ядер), швидкі transform/opacity анімації (60fps без reflow). Недоліки: додаткове споживання пам'яті (кожен layer = текстура в GPU RAM), overhead на передачу текстур CPU→GPU. Тригери: transform, opacity, will-change, <video>, <canvas>, 3D transforms." },
        ],
    },
    "JavaScript Core": {
        icon: "⚡",
        color: "#f7df1e",
        questions: [
            { level: "junior", q: "Яка різниця між `var`, `let`, `const`?", a: "`var` — function-scoped, hoisted (ініціалізується як undefined), можна перевизначити. `let` — block-scoped, hoisted але в TDZ (не можна використати до оголошення), можна reassign. `const` — block-scoped, hoisted в TDZ, не можна reassign (але об'єкти/масиви мутабельні). Рекомендація: використовувати const за замовчуванням, let коли потрібен reassign, var — ніколи." },
            { level: "junior", q: "Що таке hoisting?", a: "Hoisting — механізм JS, при якому оголошення змінних та функцій переміщуються на початок їхньої scope під час компіляції. Function declarations — повністю hoisted (можна викликати до оголошення). var — hoisted, ініціалізується як undefined. let/const — hoisted, але знаходяться в Temporal Dead Zone до рядка оголошення (ReferenceError при доступі). Class declarations — hoisted як let/const (TDZ). Function expressions та arrow functions — hoisted як змінні (залежно від var/let/const)." },
            { level: "junior", q: "Поясни замикання (closure). Наведи приклад.", a: "Замикання — функція, яка запам'ятовує змінні зі свого лексичного оточення, навіть коли виконується поза цим оточенням. Приклад: function counter() { let count = 0; return () => ++count; } const inc = counter(); inc() // 1, inc() // 2. Замикання зберігає посилання на змінну count, а не її значення. Використання: приватні змінні, фабрики функцій, каррінг, callbacks з контекстом, модульний патерн (IIFE)." },
            { level: "junior", q: "Яка різниця між `==` і `===`?", a: "`==` (Abstract Equality) — порівнює з приведенням типів (type coercion): '5' == 5 → true, null == undefined → true, '' == 0 → true. `===` (Strict Equality) — порівнює без приведення типів: '5' === 5 → false. Особливості: NaN === NaN → false (використовуй Number.isNaN). +0 === -0 → true. Рекомендація: завжди використовувати ===, єдиний виняток — перевірка null/undefined: value == null перевіряє обидва." },
            { level: "junior", q: "Що таке `this` у JS? Як воно визначається?", a: "`this` визначається в момент виклику функції, не оголошення. Правила (за пріоритетом): 1) new — this = новий об'єкт. 2) call/apply/bind — this = переданий об'єкт. 3) Метод об'єкта (obj.method()) — this = obj. 4) Проста функція — this = window (або undefined в strict mode). Arrow functions не мають свого this — беруть з лексичного оточення (де оголошені). Це робить їх ідеальними для callbacks. У класах методи без bind втрачають контекст при передачі як callback." },
            { level: "junior", q: "Поясни Event Loop. Що таке Call Stack, Microtask Queue, Task Queue?", a: "Event Loop — механізм, що дозволяє JS бути non-blocking при single-threaded виконанні. Call Stack — стек викликів функцій (LIFO). Коли стек порожній, Event Loop перевіряє черги. Microtask Queue (вищий пріоритет): Promise.then/catch/finally, queueMicrotask, MutationObserver. Виконуються ВСІ мікротаски перед наступним макротаском. Task Queue (Macrotask): setTimeout, setInterval, I/O, UI rendering. Порядок: Call Stack → всі Microtasks → один Macrotask → всі Microtasks → ..." },
            { level: "junior", q: "Що таке Promise? Як він відрізняється від callback?", a: "Promise — об'єкт, що представляє результат асинхронної операції. Стани: pending → fulfilled (resolve) або rejected (reject). Переваги над callbacks: 1) Ланцюжок (.then().then()) замість callback hell. 2) Обробка помилок через .catch() на будь-якому рівні. 3) Комбінатори: Promise.all (всі), Promise.allSettled (всі з результатами), Promise.race (перший), Promise.any (перший успішний). 4) Мікротаски — передбачуваний порядок виконання. Callback проблеми: inversion of control, pyramid of doom, складна обробка помилок." },
            { level: "junior", q: "Поясни `async/await`. Як обробляти помилки?", a: "async/await — синтаксичний цукор над Promise. async функція завжди повертає Promise. await зупиняє виконання функції до resolve Promise (не блокує event loop). Обробка помилок: 1) try/catch — найпоширеніший спосіб: try { const data = await fetch(url); } catch (err) { }. 2) .catch() на виклику: await fetchData().catch(handleError). 3) Wrapper функція: const [err, data] = await to(promise). Важливо: await у циклі — послідовне виконання, для паралельного — Promise.all([...])." },
            { level: "middle", q: "Що таке прототипне наслідування? Поясни ланцюжок прототипів.", a: "Кожен об'єкт у JS має внутрішнє посилання [[Prototype]] на інший об'єкт (прототип). При доступі до властивості JS шукає її в об'єкті, потім у прототипі, потім у прототипі прототипу — це ланцюжок прототипів (prototype chain). Закінчується на Object.prototype → null. obj.__proto__ (getter/setter) vs Object.getPrototypeOf(). Конструктор: function Foo() {} → Foo.prototype — об'єкт, який стане прототипом new Foo(). Класи ES6 — синтаксичний цукор над прототипами. Object.create(proto) — створює об'єкт з заданим прототипом." },
            { level: "middle", q: "Поясни різницю між `call`, `apply`, `bind`.", a: "Всі три методи дозволяють явно задати this для функції. `call(thisArg, arg1, arg2, ...)` — викликає функцію з переданим this та аргументами через кому. `apply(thisArg, [args])` — те ж саме, але аргументи як масив. `bind(thisArg, arg1, ...)` — НЕ викликає функцію, а повертає нову функцію з прив'язаним this та (опціонально) частковими аргументами (partial application). Bind часто використовується для передачі методів як callbacks: element.addEventListener('click', obj.method.bind(obj)). Мнемоніка: Call — Comma, Apply — Array, Bind — Later." },
            { level: "middle", q: "Що таке currying і partial application?", a: "Currying — трансформація функції f(a, b, c) у f(a)(b)(c). Кожен виклик приймає один аргумент і повертає нову функцію. Приклад: const add = a => b => a + b; add(2)(3) // 5. Partial application — фіксація частини аргументів, повертає функцію з меншою кількістю параметрів. Приклад: const add5 = add.bind(null, 5); add5(3) // 8. Різниця: curry завжди по одному аргументу, partial може фіксувати кілька. Використання: конфігурація функцій, middleware, функціональне програмування, створення спеціалізованих функцій." },
            { level: "middle", q: "Поясни деструктуризацію, spread і rest оператори.", a: "Деструктуризація — витягування значень з об'єктів/масивів: const { name, age = 25 } = user; const [first, ...rest] = arr; Вкладена: const { address: { city } } = user; Перейменування: const { name: userName } = user. Spread (...) — розпакування: [...arr1, ...arr2] (злиття масивів), { ...obj1, ...obj2 } (злиття об'єктів, shallow copy), func(...args) (розпакування аргументів). Rest (...) — збирання: function sum(...nums) {} (збирання аргументів), const { a, ...rest } = obj (решта властивостей). Spread — розпаковує, Rest — збирає." },
            { level: "middle", q: "Що таке WeakMap та WeakSet? Коли їх використовувати?", a: "WeakMap — колекція ключ-значення, де ключі — тільки об'єкти і тримаються як weak references (не перешкоджають garbage collection). WeakSet — колекція унікальних об'єктів з weak references. Відмінності від Map/Set: не ітерабельні (немає forEach, keys, values), немає size, ключі/значення можуть бути зібрані GC. Використання WeakMap: приватні дані класів, кешування результатів для об'єктів, зберігання метаданих без memory leaks, DOM-пов'язані дані. Використання WeakSet: відстеження відвіданих об'єктів, позначення об'єктів (\"вже оброблено\")." },
            { level: "middle", q: "Поясни Proxy та Reflect API. Де застосовуються?", a: "Proxy — обгортка навколо об'єкта, що перехоплює операції (traps): get, set, has, deleteProperty, apply, construct та інші. new Proxy(target, handler). Reflect — набір статичних методів, що відповідають trap-ам Proxy (Reflect.get, Reflect.set). Використовується всередині trap-ів для виклику дефолтної поведінки. Застосування: 1) Validation — перевірка значень при set. 2) Reactive systems (Vue 3 reactivity). 3) Logging/profiling доступу до властивостей. 4) Default values — повертати дефолт при відсутній властивості. 5) Immutable objects. 6) API mocking." },
            { level: "middle", q: "Що таке Symbol? Для чого використовується?", a: "Symbol — примітивний тип, кожне значення унікальне: Symbol('desc') !== Symbol('desc'). Використання: 1) Унікальні ключі об'єктів — уникнення колізій імен. 2) Well-known symbols — вбудовані: Symbol.iterator (ітерація), Symbol.toPrimitive (перетворення типів), Symbol.hasInstance (instanceof), Symbol.species (конструктор для похідних). 3) Приватні (приховані) властивості — не видно в for...in, Object.keys(), JSON.stringify(). 4) Symbol.for('key') — глобальний реєстр символів (однаковий ключ → однаковий символ). Використовується у бібліотеках для розширення без конфліктів." },
            { level: "middle", q: "Як працюють генератори та ітератори? Приклад використання.", a: "Ітератор — об'єкт з методом next(), що повертає { value, done }. Iterable — об'єкт з Symbol.iterator, що повертає ітератор (працює з for...of, spread, destructuring). Генератор (function*) — функція, що може призупиняти виконання через yield і повертає ітератор. yield повертає значення назовні, next(val) передає значення всередину. Приклади: 1) Ліниві послідовності: function* range(start, end) { for (let i = start; i <= end; i++) yield i; }. 2) Нескінченні послідовності (ID generator). 3) Async iteration (for await...of). 4) Redux-saga використовує генератори для side effects." },
            { level: "middle", q: "Що таке мемоізація? Напиши просту реалізацію.", a: "Мемоізація — кешування результату функції для однакових аргументів. Функція обчислює результат лише раз для кожного набору вхідних даних. Реалізація: function memoize(fn) { const cache = new Map(); return function(...args) { const key = JSON.stringify(args); if (cache.has(key)) return cache.get(key); const result = fn.apply(this, args); cache.set(key, result); return result; }; }. Обмеження: працює тільки з чистими функціями (без side effects), JSON.stringify не працює з об'єктами-аргументами (потрібен інший ключ), кеш росте (потрібен LRU cache для production). У React: useMemo, React.memo." },
            { level: "senior", q: "Поясни модульну систему JS: CJS, ESM, UMD. Яка різниця?", a: "CJS (CommonJS): require()/module.exports, синхронне завантаження, runtime resolution, Node.js стандарт. Копіює значення при імпорті. ESM (ES Modules): import/export, статичний аналіз (compile-time), асинхронне завантаження, live bindings (посилання на оригінал). Підтримує tree shaking. UMD (Universal Module Definition): обгортка, що працює і як CJS, і як AMD, і як глобальна змінна. Для бібліотек, що підтримують всі середовища. Ключова різниця: ESM — статичний (imports на верхньому рівні), CJS — динамічний (require в будь-якому місці). ESM — стандарт, CJS — legacy у Node.js." },
            { level: "senior", q: "Що таке Tree Shaking? Як він реалізований в bundler-ах?", a: "Tree Shaking — видалення невикористаного коду (dead code elimination) з bundle. Працює тільки з ESM (статичні import/export). Процес: 1) Bundler будує граф залежностей. 2) Аналізує, які exports використовуються. 3) Видаляє невикористаний код. Вимоги: ESM синтаксис, sideEffects: false у package.json (вказує, що модулі без side effects можна безпечно видаляти), уникати re-export всього (export * from). Проблеми: dynamic imports, side effects у модулях, CommonJS модулі не piддаються tree shaking. Webpack, Rollup, esbuild підтримують. Rollup найефективніший." },
            { level: "senior", q: "Поясни роботу V8 engine: parsing, JIT compilation, garbage collection.", a: "Parsing: Source code → AST (Abstract Syntax Tree). Lazy parsing — парсить тільки потрібний код, решту — пре-парсинг. JIT Compilation: 1) Ignition (interpreter) — швидко генерує bytecode. 2) Sparkplug — baseline compiler (швидша компіляція, менш оптимізований код). 3) TurboFan (optimizing compiler) — компілює hot functions у оптимізований machine code. Деоптимізація — якщо припущення порушені (зміна типу), повертається до bytecode. GC: Generational — Young Generation (Scavenge, часта, швидка) і Old Generation (Mark-Sweep-Compact, рідша). Incremental marking — розбиття GC на маленькі кроки. Orinoco — паралельний/конкурентний GC." },
            { level: "senior", q: "Що таке структурне клонування (structured clone algorithm)?", a: "Structured clone — алгоритм глибокого клонування об'єктів, використовується у postMessage, IndexedDB, structuredClone(). Підтримує: об'єкти, масиви, Map, Set, Date, RegExp, Blob, File, ArrayBuffer, ImageData. НЕ підтримує: функції, DOM-елементи, Symbol, прототипи (втрачає клас), Error об'єкти (обмежено), getters/setters. Обробляє циклічні посилання (на відміну від JSON.parse(JSON.stringify())). structuredClone(obj) — нативний метод (доступний у браузерах і Node.js 17+). Альтернативи: lodash cloneDeep, JSON round-trip (втрачає Date, undefined, функції)." },
            { level: "senior", q: "Поясни memory leaks у JS. Як їх виявляти та уникати?", a: "Memory leak — пам'ять, яка більше не потрібна, але не може бути звільнена GC. Причини: 1) Забуті event listeners (addEventListener без removeEventListener). 2) Замикання, що тримають великі об'єкти. 3) Глобальні змінні. 4) Detached DOM nodes — видалені з DOM, але є посилання в JS. 5) Forgotten timers (setInterval без clearInterval). 6) Circular references з closure. Виявлення: Chrome DevTools → Memory tab → Heap Snapshot, Allocation Timeline. Порівняння двох snapshots показує objects, що зросли. Performance Monitor — відстежити зростання JS Heap. Node.js: --inspect, heapdump, clinic.js." },
            { level: "senior", q: "Що таке Temporal Dead Zone (TDZ)?", a: "TDZ — проміжок від початку scope до рядка оголошення let/const, де змінна існує (hoisted) але недоступна. Доступ у TDZ → ReferenceError. Приклад: { console.log(x); // ReferenceError let x = 5; }. TDZ існує для: let, const, class, параметрів з default values. НЕ існує для: var (undefined), function declarations. Навіщо: 1) Виявляє помилки — використання до оголошення. 2) Робить const семантично правильним (інакше був би undefined до ініціалізації). 3) Мотивує правильний порядок коду. typeof у TDZ теж кидає ReferenceError (на відміну від undeclared змінних)." },
            { level: "senior", q: "Як реалізувати Observable з нуля? Чим відрізняється від Promise?", a: "Observable — lazy потік значень у часі. Реалізація: class Observable { constructor(subscribeFn) { this._subscribe = subscribeFn; } subscribe(observer) { return this._subscribe(observer); } }. Observer: { next(val), error(err), complete() }. Відмінності від Promise: 1) Lazy — не виконується без subscribe (Promise — eager). 2) Множинні значення — потік vs одне значення. 3) Cancellable — unsubscribe зупиняє (Promise не скасовується). 4) Синхронний або асинхронний (Promise завжди async). Operators: map, filter, merge, switchMap, debounceTime. Бібліотеки: RxJS. Використання: DOM events, WebSocket, HTTP polling, складна async логіка." },
            { level: "senior", q: "Поясни алгоритм порівняння об'єктів у JS (SameValue, SameValueZero, Abstract Equality).", a: "Abstract Equality (==): виконує type coercion. null == undefined → true, '' == 0 → true, '1' == 1 → true. Алгоритм: якщо типи різні — конвертує до Number (або викликає valueOf/toString). Strict Equality (===): без coercion, але NaN !== NaN, +0 === -0. SameValue (Object.is): як === але Object.is(NaN, NaN) → true, Object.is(+0, -0) → false. Використовується в Object.defineProperty. SameValueZero: як SameValue, але +0 і -0 рівні. Використовується в Map, Set, Array.includes. Для порівняння об'єктів (deep equal) потрібна рекурсивна функція або structuredClone + порівняння." },
        ],
    },
    "TypeScript": {
        icon: "🔷",
        color: "#3178c6",
        questions: [
            { level: "junior", q: "Що таке TypeScript? Яка основна перевага над JS?", a: "TypeScript — надмножина JavaScript з системою статичних типів. Компілюється в JS. Основні переваги: 1) Виявлення помилок на етапі компіляції, а не в runtime. 2) Автодоповнення та навігація в IDE. 3) Самодокументуючий код — типи описують контракти. 4) Безпечний рефакторинг — компілятор показує всі місця, які потрібно змінити. 5) Кращий tooling (IntelliSense). Не додає runtime overhead — типи стираються при компіляції. Поступовий перехід — можна мікسувати .ts і .js файли." },
            { level: "junior", q: "Поясни базові типи: string, number, boolean, any, unknown, never, void.", a: "string, number, boolean — примітивні типи. any — вимикає перевірку типів (уникати!). unknown — безпечна альтернатива any: потрібен type narrowing перед використанням. never — тип, який ніколи не має значення: функції, що кидають error або мають нескінченний цикл; exhaustive checks у switch. void — відсутність значення, зазвичай return type функцій, що нічого не повертають. null і undefined — окремі типи. Рекомендація: strictNullChecks: true, уникати any на користь unknown, використовувати never для exhaustive checks." },
            { level: "junior", q: "Що таке interface vs type alias? Яка різниця?", a: "Interface: описує форму об'єкта, підтримує declaration merging (автоматичне об'єднання однойменних інтерфейсів), extends для наслідування. Type alias: може описувати будь-який тип (unions, intersections, primitives, tuples), використовує & для об'єднання, не підтримує merging. Ключові відмінності: 1) interface — declaration merging (корисно для бібліотек). 2) type — unions (type A = B | C), mapped types, conditional types. 3) interface extends — трохи кращий performance компілятора. Рекомендація: interface для об'єктів/класів, type для всього іншого." },
            { level: "junior", q: "Що таке union і intersection types?", a: "Union (A | B) — значення може бути типу A АБО B. Приклад: type Status = 'loading' | 'success' | 'error'; function handle(input: string | number). Потрібен type narrowing для доступу до специфічних властивостей. Intersection (A & B) — значення має бути типу A І B одночасно. Приклад: type Employee = Person & { company: string }. Об'єднує всі властивості обох типів. Для примітивів intersection часто дає never (string & number = never). Union — для варіантів, Intersection — для комбінування." },
            { level: "junior", q: "Що таке generics? Наведи простий приклад.", a: "Generics — параметризовані типи, що дозволяють створювати переиспользовувані компоненти, які працюють з різними типами, зберігаючи type safety. Приклад: function identity<T>(arg: T): T { return arg; } identity<string>('hello'); identity(42) — T виводиться як number. Generics у інтерфейсах: interface Box<T> { value: T; }. Обмеження: function getLength<T extends { length: number }>(arg: T): number { return arg.length; }. Дефолт: type Container<T = string> = { value: T }. Використання: колекції, Promise<T>, React компоненти, API responses." },
            { level: "junior", q: "Що таке enum? Коли використовувати const enum?", a: "Enum — набір іменованих констант. Numeric enum: enum Direction { Up, Down } (0, 1). String enum: enum Status { Active = 'ACTIVE' }. Enum компілюється в об'єкт JS (зворотне маппування для numeric). const enum — інлайниться при компіляції (замінюється на значення), не створює об'єкт у runtime. Менший bundle, але не працює з isolatedModules. Альтернативи enum: 1) as const: const STATUS = { Active: 'ACTIVE' } as const — працює з tree shaking. 2) Union types: type Status = 'active' | 'inactive'. Рекомендація: string unions або as const замість enum." },
            { level: "middle", q: "Поясни utility types: Partial, Required, Readonly, Pick, Omit, Record, Exclude, Extract.", a: "Partial<T> — всі поля optional. Required<T> — всі поля обов'язкові. Readonly<T> — всі поля readonly. Pick<T, Keys> — вибирає зазначені ключі: Pick<User, 'id' | 'name'>. Omit<T, Keys> — виключає ключі: Omit<User, 'password'>. Record<Keys, Value> — об'єкт з ключами Keys і значеннями Value: Record<string, number>. Exclude<Union, Excluded> — виключає з union: Exclude<'a'|'b'|'c', 'a'> = 'b'|'c'. Extract<Union, Matched> — витягує з union: Extract<'a'|'b'|1, string> = 'a'|'b'. Також: NonNullable<T>, ReturnType<F>, Parameters<F>, Awaited<T>." },
            { level: "middle", q: "Що таке mapped types? Напиши приклад свого mapped type.", a: "Mapped types — створення нового типу шляхом трансформації ключів існуючого. Синтаксис: { [K in keyof T]: NewType }. Приклад: type Optional<T> = { [K in keyof T]?: T[K] } (аналог Partial). Модифікатори: +/- readonly, +/- optional. type Mutable<T> = { -readonly [K in keyof T]: T[K] }. Key remapping (as): type Getters<T> = { [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K] }. Для { name: string } → { getName: () => string }. Фільтрація ключів: type OnlyStrings<T> = { [K in keyof T as T[K] extends string ? K : never]: T[K] }." },
            { level: "middle", q: "Що таке conditional types? Поясни `infer`.", a: "Conditional types: T extends U ? X : Y — якщо T assignable до U, результат X, інакше Y. Приклад: type IsString<T> = T extends string ? true : false. Distributive: union типи розподіляються: IsString<string | number> = true | false. infer — витягує тип зсередини іншого типу: type ReturnType<T> = T extends (...args: any[]) => infer R ? R : never. Витягує return type функції. type ElementType<T> = T extends Array<infer E> ? E : T — витягує тип елемента масиву. type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T — рекурсивно розгортає Promise." },
            { level: "middle", q: "Що таке discriminated unions? Де це корисно?", a: "Discriminated union — union тип, де кожен варіант має спільне literal поле (дискримінант), яке дозволяє TypeScript точно визначити тип. Приклад: type Action = { type: 'ADD'; item: string } | { type: 'REMOVE'; id: number }. При switch(action.type) TS автоматично звужує тип у кожному case. Корисно: 1) Redux actions. 2) API responses: { status: 'success'; data: T } | { status: 'error'; error: string }. 3) State machines. 4) AST nodes. Exhaustive check: default: const _: never = action — помилка компіляції, якщо не всі варіанти оброблені." },
            { level: "middle", q: "Поясни type narrowing: typeof, instanceof, in, discriminated union.", a: "Type narrowing — звуження типу до конкретнішого. typeof: if (typeof x === 'string') — працює для примітивів. instanceof: if (x instanceof Date) — для класів. in: if ('name' in obj) — перевірка наявності властивості. Discriminated union: switch на дискримінантному полі. Також: truthiness check (if (x) виключає null/undefined/0/\"\"), equality check (if (x === null)), custom type guards: function isString(x: unknown): x is string { return typeof x === 'string'; }. Asserts: function assertString(x: unknown): asserts x is string { if (typeof x !== 'string') throw new Error(); }." },
            { level: "middle", q: "Що таке declaration merging?", a: "Declaration merging — автоматичне об'єднання кількох оголошень з однаковим ім'ям в одне. Працює для interface (додає нові поля), namespace (об'єднує), enum (додає members). Приклад: interface User { name: string; } interface User { age: number; } → User має name і age. Не працює для type aliases — помилка duplicate identifier. Використання: 1) Розширення типів бібліотек (augmentation). 2) Polyfills — додавання методів до існуючих інтерфейсів. 3) Plugin архітектура. Module augmentation: declare module 'express' { interface Request { user: User; } }." },
            { level: "middle", q: "Поясни `keyof`, `typeof`, `ReturnType`, `Parameters`.", a: "keyof T — union всіх ключів типу T: keyof { name: string; age: number } = 'name' | 'age'. Використовується з generics: function get<T, K extends keyof T>(obj: T, key: K): T[K]. typeof — отримує тип зі значення: const user = { name: 'John' }; type User = typeof user; Корисно з as const. ReturnType<T> — витягує return type функції: type R = ReturnType<typeof fetchUser>. Parameters<T> — tuple типів параметрів: type P = Parameters<typeof fn> → [string, number]. Також: ConstructorParameters<T>, InstanceType<T>, ThisParameterType<T>." },
            { level: "middle", q: "Що таке module augmentation? Як розширити типи сторонньої бібліотеки?", a: "Module augmentation — розширення типів модуля без зміни його коду. Синтаксис: declare module 'module-name' { interface ExistingInterface { newProp: string; } }. Приклад (Express): declare module 'express' { interface Request { user?: User; currentLocale: string; } }. Файл має бути модулем (містити import/export). Global augmentation: declare global { interface Window { myVar: string; } }. Правила: можна тільки додавати нові властивості до існуючих інтерфейсів (declaration merging), не можна змінювати існуючі типи або використовувати type alias." },
            { level: "senior", q: "Поясни Template Literal Types. Де вони корисні?", a: "Template Literal Types — типи на основі шаблонних рядків: type Greeting = `hello ${string}`. З union розподіляються: type Color = 'red' | 'blue'; type BgColor = `bg-${Color}` = 'bg-red' | 'bg-blue'. Intrinsic string manipulation: Uppercase, Lowercase, Capitalize, Uncapitalize. Використання: 1) Event names: type EventName = `on${Capitalize<string>}`. 2) CSS utilities: `${number}px` | `${number}rem`. 3) Типізовані routes: `/users/${number}/posts/${number}`. 4) Getters/setters: `get${Capitalize<keyof T>}`. 5) Типізований i18n: translation keys. Обмеження: складні template literals можуть сповільнити компілятор." },
            { level: "senior", q: "Що таке variance (covariance, contravariance) у TypeScript?", a: "Variance визначає, як підтипи контейнерних типів співвідносяться з підтипами їх вмісту. Covariance (out) — якщо A extends B, то Container<A> extends Container<B>. Масиви коваріантні: string[] assignable до (string|number)[]. Contravariance (in) — якщо A extends B, то Container<B> extends Container<A>. Параметри функцій контраваріантні (з strictFunctionTypes): (x: string|number) => void assignable до (x: string) => void. Invariance — ні covariant, ні contravariant. Bivariance — і те, і інше (TypeScript без strict для методів). TS 4.7: in/out модифікатори для явної variance: interface Box<out T> { get(): T }." },
            { level: "senior", q: "Як реалізувати DeepReadonly<T> рекурсивно?", a: "type DeepReadonly<T> = T extends Function ? T : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> } : T. Це рекурсивно робить readonly всі вкладені властивості. Для primitive — повертає як є. Для функцій — повертає як є (readonly не має сенсу). Для об'єктів/масивів — рекурсивно застосовує readonly. Покращена версія з підтримкою Map/Set: type DeepReadonly<T> = T extends Map<infer K, infer V> ? ReadonlyMap<DeepReadonly<K>, DeepReadonly<V>> : T extends Set<infer U> ? ReadonlySet<DeepReadonly<U>> : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> } : T." },
            { level: "senior", q: "Поясни `satisfies` оператор і коли він кращий за звичайну анотацію.", a: "satisfies (TS 4.9) — перевіряє, що вираз відповідає типу, але зберігає інферований тип (вужчий). Анотація const x: Type = value — тип буде Type. satisfies: const x = value satisfies Type — тип буде inferring з value. Приклад: type Colors = Record<string, [number, number, number] | string>; const palette = { red: [255, 0, 0], green: '#00ff00' } satisfies Colors. Тепер palette.red — tuple [number, number, number] (не string | tuple), palette.green — string. Анотація втратила б цю конкретику. Корисно: конфігурації, маппінги, де потрібна і валідація, і точні типи." },
            { level: "senior", q: "Що таке branded types / nominal typing? Як реалізувати в TS?", a: "TypeScript використовує structural typing — типи сумісні, якщо структура збігається. Branded types додають \"бренд\" для номінальної типізації. Реалізація: type USD = number & { readonly __brand: 'USD' }; type EUR = number & { readonly __brand: 'EUR' }. Тепер USD і EUR несумісні, хоча обидва number. Створення: const usd = (amount: number) => amount as USD. Використання: 1) Валюти (USD vs EUR). 2) ID типи (UserId vs PostId). 3) Validated strings (Email, URL). 4) Одиниці виміру (Meters vs Feet). Запобігає помилкам змішування семантично різних значень одного примітивного типу." },
            { level: "senior", q: "Поясни як TypeScript перевіряє типи структурально (structural typing) і де це може бути проблемою.", a: "Structural typing — типи сумісні, якщо мають однакову структуру (shape), незалежно від імені. Приклад: interface Cat { name: string } interface Dog { name: string } — Cat і Dog взаємозамінні. Проблеми: 1) Зайві властивості — { name: 'John', age: 25, admin: true } assignable до { name: string } (excess property check тільки для object literals). 2) Плутанина семантики — UserId і PostId (обидва number) взаємозамінні (вирішується branded types). 3) Класи з однаковою структурою сумісні. 4) Функції — менше параметрів assignable до більше (callback safety). Рішення: branded types, private fields у класах (#field робить тип номінальним)." },
            { level: "senior", q: "Як написати тип, який витягує всі шляхи до вкладених ключів об'єкта (deep path type)?", a: "type Path<T> = T extends object ? { [K in keyof T & string]: K | `${K}.${Path<T[K]>}` }[keyof T & string] : never. Для { user: { address: { city: string } } } дає: 'user' | 'user.address' | 'user.address.city'. Використання: типізований доступ до вкладених полів (lodash get, i18n ключі, form field paths). Покращена версія з типом значення: type PathValue<T, P extends Path<T>> = P extends `${infer K}.${infer Rest}` ? K extends keyof T ? Rest extends Path<T[K]> ? PathValue<T[K], Rest> : never : never : P extends keyof T ? T[P] : never. Обмеження: глибока рекурсія може сповільнити компілятор — обмежуйте глибину." },
        ],
    },
    "React": {
        icon: "⚛️",
        color: "#61dafb",
        questions: [
            { level: "junior", q: "Що таке Virtual DOM? Як він працює?", a: "Virtual DOM — легковаговане JS-представлення реального DOM. При зміні state React створює новий VDOM tree, порівнює з попереднім (diffing/reconciliation) і застосовує мінімальні зміни до реального DOM (patching). Переваги: 1) Batching — кілька змін об'єднуються в одне оновлення. 2) Абстракція — розробник описує ЩО показати, React вирішує ЯК оновити. 3) Cross-platform — той самий VDOM для web (ReactDOM), mobile (React Native), SSR. VDOM — не швидший за ручні DOM-маніпуляції, але дає декларативний підхід з прийнятною продуктивністю." },
            { level: "junior", q: "Яка різниця між класовими та функціональними компонентами?", a: "Класові: class Comp extends React.Component, state через this.state/setState, lifecycle methods (componentDidMount, componentDidUpdate, componentWillUnmount), this контекст. Функціональні: звичайні функції, state через useState, effects через useEffect, hooks замість lifecycle. Ключові відмінності: 1) Функціональні простіші і коротші. 2) Hooks дозволяють reuse логіки (custom hooks) — неможливо з класами (HOC/render props були складнішими). 3) Функціональні захоплюють props/state на момент рендеру (немає stale this). 4) Класи все ще потрібні для Error Boundaries. React рекомендує функціональні компоненти." },
            { level: "junior", q: "Що таке JSX? Як він трансформується?", a: "JSX — синтаксичне розширення JS, яке дозволяє писати HTML-подібний код у JS. Трансформація (Babel/SWC): <Button color='blue'>Click</Button> → React.createElement(Button, { color: 'blue' }, 'Click') (classic) або _jsx(Button, { color: 'blue', children: 'Click' }) (automatic runtime, React 17+). JSX — не рядок і не HTML, а виклик функцій, що повертають React Elements (plain objects: { type, props, key }). Обмеження: className замість class, htmlFor замість for, camelCase для атрибутів, обов'язкове закриття тегів, один кореневий елемент (або Fragment)." },
            { level: "junior", q: "Поясни useState та useEffect. Коли useEffect спрацьовує?", a: "useState(initialValue) — повертає [value, setter]. setter може приймати нове значення або функцію (prev => newValue). Оновлення асинхронне (batched). useEffect(callback, deps) — для side effects (API calls, підписки, DOM маніпуляції). Спрацьовує: 1) Без deps — після кожного рендеру. 2) [] — один раз після mount (аналог componentDidMount). 3) [dep1, dep2] — при зміні залежностей. Cleanup функція (return) — викликається перед наступним ефектом і при unmount. Порівняння deps через Object.is (shallow). useEffect виконується асинхронно після paint." },
            { level: "junior", q: "Що таке props та state? Яка різниця?", a: "Props — дані, передані компоненту від батька. Immutable — компонент не може змінювати свої props. Використовуються для конфігурації та передачі даних вниз по дереву. State — внутрішні дані компонента. Mutable через setState/useState. Зміна state викликає re-render. Ключові відмінності: props — зовнішні, read-only; state — внутрішній, змінюваний. Props flow down (від батька до дитини), events flow up (дитина викликає callback з props). State потрібен для: інтерактивних елементів (форми, toggles), даних з API, UI стану (open/close, loading)." },
            { level: "junior", q: "Що таке key у списках? Навіщо він потрібен?", a: "Key — унікальний ідентифікатор елемента в списку, який допомагає React ефективно оновлювати DOM при reconciliation. Без key React порівнює елементи по порядку (index), що призводить до: 1) Неправильного оновлення при додаванні/видаленні/переміщенні елементів. 2) Втрати стану компонентів. 3) Зайвих ре-рендерів. Правила: key має бути стабільним (не random), унікальним серед siblings, ідеально — id з даних. Антипатерн: index як key — працює тільки для статичних списків без reorder. Key також можна використовувати для reset state компонента: змінив key → компонент перемонтується." },
            { level: "junior", q: "Що таке controlled та uncontrolled компоненти?", a: "Controlled — React контролює значення input через state: value={state} onChange={e => setState(e.target.value)}. Кожна зміна проходить через React. Переваги: validation в реальному часі, форматування, conditional logic. Uncontrolled — DOM сам зберігає значення, доступ через ref: const inputRef = useRef(); inputRef.current.value. Переваги: простіше для простих форм, менше ре-рендерів. defaultValue замість value. Коли що: Controlled — більшість випадків (форми з validation, динамічні UI). Uncontrolled — file input (завжди uncontrolled), прості форми, інтеграція з non-React кодом." },
            { level: "middle", q: "Поясни useCallback та useMemo. Коли їх використовувати, а коли ні?", a: "useMemo(fn, deps) — мемоізує РЕЗУЛЬТАТ обчислення. Перераховує тільки при зміні deps. useCallback(fn, deps) — мемоізує САМУ ФУНКЦІЮ (useCallback(fn, deps) === useMemo(() => fn, deps)). Коли використовувати: 1) useCallback — передача callback у React.memo компонент (інакше нова функція → ре-рендер). 2) useMemo — дороге обчислення (фільтрація, сортування великих масивів). 3) Стабільна посилка для deps іншого хука. Коли НЕ використовувати: дешеві обчислення, функції не передаються як props, premature optimization. Мемоізація має свою ціну (пам'ять, порівняння deps)." },
            { level: "middle", q: "Що таке useRef? Які є сценарії використання крім DOM?", a: "useRef(initialValue) — повертає мутабельний об'єкт { current: value }, який зберігається між рендерами. Зміна .current НЕ викликає ре-рендер. DOM: const ref = useRef(); <input ref={ref} /> → ref.current = DOM element. Інші сценарії: 1) Збереження попереднього значення (prevValue). 2) Instance variables — зберігання timer ID, WebSocket instance, AbortController. 3) Підрахунок рендерів (debug). 4) Прапорець isMounted (уникання setState на unmounted). 5) Доступ до останнього значення state/props всередині callback (уникнення stale closure). useRef — мутабельна \"коробка\", яка не впливає на рендер." },
            { level: "middle", q: "Поясни Context API. Які проблеми він вирішує та які створює?", a: "Context API — механізм передачі даних через дерево компонентів без prop drilling. createContext(default) → Provider (надає значення) → useContext(Context) (споживає). Вирішує: передачу \"глобальних\" даних (тема, locale, auth user) глибоко вкладеним компонентам. Проблеми: 1) Ре-рендер ВСІХ споживачів при зміні будь-якої частини context value (навіть якщо компонент використовує тільки частину). 2) Не підходить для часто змінюваних даних. 3) Складність дебагу. Рішення: розділяти context на менші, мемоізувати value (useMemo), використовувати state managers (Zustand, Jotai) для частих оновлень." },
            { level: "middle", q: "Що таке useReducer? Коли він кращий за useState?", a: "useReducer(reducer, initialState) — альтернатива useState для складної логіки стану. reducer(state, action) → newState. Повертає [state, dispatch]. Кращий за useState коли: 1) Стан — об'єкт з кількома пов'язаними полями. 2) Наступний стан залежить від попереднього. 3) Складна логіка оновлення (switch по action types). 4) Потрібно передати dispatch замість кількох callbacks (dispatch стабільний). Патерн: поєднання з Context — dispatch через context уникає prop drilling callbacks. Схожий на Redux reducer, але локальний. useState — для простого стану (boolean, string, number)." },
            { level: "middle", q: "Що таке React.memo? Як він працює? Яка різниця з useMemo?", a: "React.memo(Component) — HOC, що мемоізує КОМПОНЕНТ. Пропускає ре-рендер, якщо props не змінились (shallow comparison). Можна передати custom comparator: React.memo(Comp, (prevProps, nextProps) => areEqual). useMemo — мемоізує ЗНАЧЕННЯ всередині компонента. Різниця: React.memo — обгортка компонента (запобігає ре-рендеру), useMemo — хук (запобігає перерахунку). React.memo не працює якщо: 1) Передається новий об'єкт/масив/функція як prop (потрібен useMemo/useCallback). 2) Компонент використовує useContext — зміна context ігнорує memo. React.memo корисний для дорогих компонентів у списках." },
            { level: "middle", q: "Поясни reconciliation алгоритм React (diffing).", a: "Reconciliation — процес порівняння двох VDOM дерев для визначення мінімальних змін. Два ключових припущення (O(n) замість O(n³)): 1) Елементи різних типів → повне перемонтування піддерева (div→span = destroy + create). 2) Key вказує на стабільність елемента між рендерами. Для однакового типу: оновлює тільки змінені атрибути. Для списків: використовує key для маппінгу старих і нових елементів, визначає переміщення, додавання, видалення. Без key — порівнює по індексу (неефективно при вставці на початок). React Fiber дозволив розбити reconciliation на chunks для concurrent rendering." },
            { level: "middle", q: "Що таке Error Boundary? Як реалізувати?", a: "Error Boundary — класовий компонент, що перехоплює JS помилки в дочірньому дереві і показує fallback UI замість crashу всього додатку. Реалізація: class ErrorBoundary extends React.Component { state = { hasError: false }; static getDerivedStateFromError(error) { return { hasError: true }; } componentDidCatch(error, info) { logError(error, info); } render() { return this.state.hasError ? <Fallback /> : this.props.children; } }. НЕ ловить: помилки в event handlers (використовуй try/catch), async код, SSR, самому Error Boundary. Немає хука-аналогу — тільки класові компоненти. Бібліотека react-error-boundary спрощує використання." },
            { level: "middle", q: "Поясни lifting state up та prop drilling. Як їх вирішувати?", a: "Lifting state up — переміщення state у найближчого спільного батька, коли кілька компонентів потребують однакових даних. Батько керує state, передає через props. Prop drilling — проблема, коли props передаються через багато рівнів компонентів, які самі їх не використовують. Рішення: 1) Context API — для рідко змінюваних даних (тема, auth). 2) Composition (children pattern) — передавати готові компоненти замість даних. 3) State management (Zustand, Redux) — для складного стану. 4) Component composition — restructure дерево, щоб зменшити глибину. 5) Render props / HOC. Кращий підхід залежить від масштабу проблеми." },
            { level: "middle", q: "Що таке Custom Hooks? Напиши приклад useFetch.", a: "Custom Hooks — функції з префіксом use, що інкапсулюють reusable логіку з хуками. Правила: викликати тільки на верхньому рівні, тільки в компонентах або інших хуках. Приклад useFetch: function useFetch<T>(url: string) { const [data, setData] = useState<T | null>(null); const [loading, setLoading] = useState(true); const [error, setError] = useState<Error | null>(null); useEffect(() => { const controller = new AbortController(); fetch(url, { signal: controller.signal }).then(res => res.json()).then(setData).catch(setError).finally(() => setLoading(false)); return () => controller.abort(); }, [url]); return { data, loading, error }; }. Custom hooks дозволяють ділити логіку між компонентами без зміни ієрархії." },
            { level: "middle", q: "Що таке React.lazy та Suspense? Як реалізувати code splitting?", a: "React.lazy(() => import('./Component')) — динамічний імпорт компонента, створює окремий chunk. Suspense — обгортка, що показує fallback під час завантаження lazy компонента. <Suspense fallback={<Spinner />}><LazyComponent /></Suspense>. Code splitting стратегії: 1) Route-based — lazy load сторінок (найпоширеніший). 2) Component-based — важкі компоненти (модалки, графіки). 3) Feature-based — за функціональністю. Webpack автоматично створює chunks для dynamic imports. З React 18 Suspense також працює з data fetching (React Query, use() hook). Next.js має вбудований code splitting по сторінках." },
            { level: "middle", q: "Що таке Portals? Коли їх використовувати?", a: "Portal — механізм рендеру дочірніх елементів у DOM-вузол за межами батьківського компонента. ReactDOM.createPortal(children, domNode). Дитина рендериться в domNode, але залишається частиною React-дерева (events bubble up через React tree, context працює). Використання: 1) Модальні вікна — рендер поверх всього, уникаючи z-index/overflow проблем. 2) Tooltips та popovers. 3) Notifications/toasts. 4) Floating menus. Типовий паттерн: портал рендериться в document.body або спеціальний div#modal-root. Event bubbling через портал: клік у модалі спливає до React-батька, не до DOM-батька." },
            { level: "senior", q: "Поясни React Fiber architecture. Що таке work loop, fiber node, lanes?", a: "Fiber — переписана архітектура React (з v16), де кожен елемент представлений Fiber Node — об'єктом з полями: type, props, stateNode, child, sibling, return, alternate (для double buffering). Work loop — цикл обробки fiber nodes. Дві фази: 1) Render (reconciliation) — traversal дерева, можна переривати (interruptible). 2) Commit — застосування змін до DOM (synchronous, не переривається). Lanes — система пріоритетів (замість expiration times у старих версіях). Кожне оновлення отримує lane (SyncLane, DefaultLane, TransitionLane, IdleLane). Lanes — бітові маски, що дозволяють ефективно об'єднувати та порівнювати пріоритети. Concurrent features працюють завдяки можливості переривати render phase." },
            { level: "senior", q: "Що таке Concurrent Mode? Поясни `useTransition` та `useDeferredValue`.", a: "Concurrent Mode (React 18+) — React може переривати рендеринг, працювати над кількома оновленнями одночасно та пріоритизувати їх. useTransition: const [isPending, startTransition] = useTransition(). startTransition(() => setState(newValue)) — позначає оновлення як низькопріоритетне (transition). UI залишається responsive, isPending показує стан. Приклад: фільтрація великого списку — input оновлюється одразу, список — в transition. useDeferredValue(value) — повертає відкладену версію значення. React спочатку рендерить зі старим значенням (швидко), потім з новим (у фоні). Схоже на debounce, але розумніше — адаптується до потужності пристрою." },
            { level: "senior", q: "Що таке React Server Components? Яка різниця між 'use client' та 'use server'?", a: "React Server Components (RSC) — компоненти, що виконуються тільки на сервері. Не відправляють JS клієнту, можуть напряму звертатись до БД/файлової системи. 'use client' — маркер, що компонент та його імпорти входять у client bundle (потрібен для useState, useEffect, event handlers, browser APIs). 'use server' — маркер для Server Actions (функції, що викликаються з клієнта, виконуються на сервері). Ключова різниця: Server Components — default у App Router, zero JS bundle impact, async (можуть await). Client Components — інтерактивність, hooks, browser API. Не можна імпортувати Server Component у Client Component (тільки через children)." },
            { level: "senior", q: "Поясни batching у React 18. Чим відрізняється від React 17?", a: "Batching — об'єднання кількох setState в одне оновлення (один ре-рендер). React 17: batching тільки в React event handlers. Поза ними (setTimeout, fetch.then, native events) — кожен setState = окремий ре-рендер. React 18 (Automatic Batching): batching ВСЮДИ — setTimeout, promises, native events, будь-який асинхронний код. createRoot() активує automatic batching. Приклад: setTimeout(() => { setA(1); setB(2); }, 0) — React 17: 2 ре-рендери, React 18: 1. Якщо потрібно примусове оновлення: flushSync(() => setState(val)) — обходить batching. Покращує performance без змін коду." },
            { level: "senior", q: "Як React визначає чи потрібно ре-рендерити компонент? Поясни стратегію bailout.", a: "React ре-рендерить компонент коли: 1) setState з новим значенням (Object.is порівняння). 2) Батьківський компонент ре-рендериться. 3) Context value змінився. Bailout — оптимізація, коли React пропускає ре-рендер: 1) setState з тим самим значенням (Object.is) — React може почати рендер, але bailout якщо результат ідентичний (early bailout). 2) React.memo — shallow порівняння props. 3) useMemo — запобігає створенню нових об'єктів у props. Важливо: навіть при bailout React може викликати render функцію компонента (для перевірки), але не оновить DOM. Children prop — якщо children стабільний (не створений у render), дитина не ре-рендериться." },
            { level: "senior", q: "Що таке Strict Mode? Чому він двічі запускає ефекти в dev режимі?", a: "StrictMode — dev-only інструмент для виявлення потенційних проблем. Подвійний виклик: 1) Render functions — виявляє side effects у render. 2) useEffect — mount → unmount → mount — перевіряє правильність cleanup. 3) useState initializer — перевіряє чистоту. Навіщо подвійні ефекти: React 18 Concurrent Features можуть mount/unmount компоненти (Offscreen API, Suspense). Якщо ефект не має правильного cleanup — буде баг. Подвійний виклик в dev виявляє це заздалегідь. Приклад: підписка без відписки — при подвійному виклику буде 2 підписки. Strict Mode НЕ впливає на production build." },
            { level: "senior", q: "Як правильно організувати state management у великому додатку? Порівняй підходи.", a: "Категорії state: 1) Local UI state (модалки, toggles) — useState/useReducer. 2) Server state (дані з API) — React Query/SWR (кешування, refetching, optimistic updates). 3) Global client state (тема, auth) — Zustand (простий) або Redux Toolkit (складний). 4) URL state — router params/search params. 5) Form state — React Hook Form / Formik. Порівняння: Redux Toolkit — найбільший ecosystem, middleware, DevTools, boilerplate. Zustand — мінімальний API, no providers, менше boilerplate. Jotai — атомарний, bottom-up, ідеальний для derived state. Context — тільки для рідко змінюваних даних. Принцип: тримати state якомога ближче до місця використання." },
            { level: "senior", q: "Поясни stale closure проблему в React. Як її уникнути?", a: "Stale closure — коли функція (callback, effect) захоплює старе значення state/props через замикання і не бачить оновлень. Приклад: useEffect(() => { setInterval(() => console.log(count), 1000); }, []) — count завжди 0. Рішення: 1) Додати залежність в deps: [count]. 2) Functional update: setCount(prev => prev + 1) — не залежить від замикання. 3) useRef для поточного значення: const countRef = useRef(count); countRef.current = count; — завжди актуальне. 4) useCallback з правильними deps. Причина: кожен рендер створює нове замикання з поточними значеннями, але старі callbacks/ефекти тримають старе замикання." },
            { level: "senior", q: "Що таке `use` hook (RFC)? Як він змінює підхід до data fetching?", a: "use() — новий hook (React 19), що може читати значення з Promise або Context. Відмінності: 1) Можна викликати умовно (if/else) — єдиний хук з таким правом. 2) use(promise) — Suspense для data fetching без useEffect. 3) use(context) — альтернатива useContext, з умовним використанням. Data fetching: замість useEffect + useState (loading, error, data), компонент просто: const data = use(fetchPromise). Suspense показує fallback під час завантаження, ErrorBoundary ловить помилки. Promise має бути створений поза компонентом (або кешований) — не створювати в render. Інтеграція з React Server Components та серверний prefetching." },
        ],
    },
    "Next.js": {
        icon: "▲",
        color: "#ffffff",
        questions: [
            { level: "junior", q: "Що таке Next.js? Яка головна перевага над CRA?", a: "Next.js — React фреймворк з SSR, SSG, file-based routing, API routes, оптимізаціями з коробки. Переваги над CRA: 1) SEO — SSR/SSG генерують HTML на сервері (CRA — порожній div до завантаження JS). 2) Performance — automatic code splitting, image optimization, font optimization. 3) Routing — файлова система замість react-router конфігурації. 4) Full-stack — API routes, Server Actions, middleware. 5) Deployment — оптимізований для Vercel, але працює будь-де. CRA — deprecated, Next.js — рекомендований React спосіб створення додатків." },
            { level: "junior", q: "Яка різниця між SSR, SSG, ISR та CSR?", a: "CSR (Client-Side Rendering) — JS завантажується, рендерить на клієнті. Швидкий TTFB, повільний FCP. SPA. SSR (Server-Side Rendering) — HTML генерується на сервері ПРИ КОЖНОМУ запиті. Завжди актуальні дані, повільніший TTFB. getServerSideProps. SSG (Static Site Generation) — HTML генерується на етапі BUILD. Найшвидший, але дані статичні. getStaticProps. ISR (Incremental Static Regeneration) — SSG + revalidation. Сторінка регенерується у фоні через N секунд. revalidate: 60 — оновлення кожні 60с. Найкращий баланс швидкості та актуальності для контентних сайтів." },
            { level: "junior", q: "Поясни файлову систему роутингу Next.js.", a: "Next.js використовує файлову структуру для визначення роутів. Pages Router: pages/index.tsx → /, pages/about.tsx → /about, pages/posts/[id].tsx → /posts/:id. App Router (13+): app/page.tsx → /, app/about/page.tsx → /about, app/posts/[id]/page.tsx → /posts/:id. Спеціальні файли App Router: layout.tsx (shared layout), loading.tsx (Suspense fallback), error.tsx (Error Boundary), not-found.tsx (404). Route groups: (marketing)/about — групування без впливу на URL. Parallel routes: @modal — одночасний рендер кількох сторінок. Intercepting routes: (.)photo — перехоплення роутів." },
            { level: "junior", q: "Що таке `getStaticProps` та `getServerSideProps`?", a: "getStaticProps (Pages Router) — виконується на етапі build, генерує статичний HTML. Дані вбудовуються в сторінку. props передаються компоненту. revalidate — ISR інтервал. getStaticPaths — визначає динамічні шляхи для SSG. fallback: false/true/'blocking'. getServerSideProps — виконується на сервері при КОЖНОМУ запиті. Має доступ до req/res, cookies, headers. Повільніший (TTFB), але завжди актуальні дані. В App Router: getStaticProps → default (static), getServerSideProps → dynamic (force-dynamic або cookies()/headers()). fetch з cache/revalidate опціями замінює обидва." },
            { level: "middle", q: "Що таке App Router у Next.js 13+? Яка різниця з Pages Router?", a: "App Router — нова система маршрутизації в директорії app/. Ключові відмінності: 1) Server Components за замовчуванням (vs Client у Pages Router). 2) Nested layouts — layout.tsx зберігає стан при навігації. 3) Streaming SSR — loading.tsx + Suspense. 4) Colocation — компоненти, стилі, тести поруч з роутом. 5) Server Actions — мутації без API routes. 6) Parallel routes (@slot) та intercepting routes. 7) fetch замість getStaticProps/getServerSideProps. Pages Router: getServerSideProps/getStaticProps, _app.tsx/_document.tsx, повністю клієнтські компоненти. App Router — рекомендований для нових проєктів." },
            { level: "middle", q: "Поясни layouts у App Router. Що таке nested layouts?", a: "Layout — UI, спільний для групи роутів. app/layout.tsx — root layout (обов'язковий, містить html/body). app/dashboard/layout.tsx — layout для /dashboard/*. Nested layouts: дочірні layouts вкладаються в батьківські. При навігації між /dashboard/analytics і /dashboard/settings — dashboard layout НЕ перерендерюється (зберігає state). Це ключова перевага: shared navigation, sidebar, header. Layout отримує children prop. template.tsx — як layout, але створює НОВИЙ instance при навігації (re-mount). Використання: auth перевірки в layout, sidebar, breadcrumbs. Layout не має доступу до pathname (використовуй usePathname в client component)." },
            { level: "middle", q: "Що таке Server Components у Next.js? Коли використовувати 'use client'?", a: "Server Components (default в App Router) — рендеряться на сервері, НЕ відправляють JS клієнту. Можуть: async/await, прямий доступ до БД/файлів, безпечно використовувати секрети. Не можуть: useState, useEffect, event handlers, browser APIs. 'use client' потрібен коли: 1) Інтерактивність — onClick, onChange, форми. 2) Hooks — useState, useEffect, useContext. 3) Browser APIs — localStorage, window, IntersectionObserver. 4) Сторонні бібліотеки з hooks. Стратегія: максимум Server Components, 'use client' — тільки для листових інтерактивних компонентів. Не ставити 'use client' на високому рівні — це робить все піддерево клієнтським." },
            { level: "middle", q: "Що таке Route Handlers (API routes)? Як обробляти різні методи?", a: "Route Handlers — серверні ендпоінти в App Router. Файл: app/api/users/route.ts. Експортуються функції за HTTP методом: export async function GET(request: Request) { return Response.json(data); } export async function POST(request: Request) { const body = await request.json(); return Response.json(result, { status: 201 }); }. Підтримуються: GET, POST, PUT, PATCH, DELETE, HEAD, OPTIONS. Request — стандартний Web API Request. Доступ до params: app/api/users/[id]/route.ts — (request, { params }). Cookies: cookies(), Headers: headers(). Caching: GET без cookies кешується, POST ніколи. Замінюють pages/api у App Router." },
            { level: "middle", q: "Поясни Image та Font оптимізацію у Next.js.", a: "next/image (Image компонент): 1) Automatic format — WebP/AVIF. 2) Responsive sizes — srcSet автоматично. 3) Lazy loading за замовчуванням. 4) Placeholder blur — розмитий preview під час завантаження. 5) Запобігає CLS — обов'язкові width/height або fill. 6) On-demand optimization — зображення оптимізуються при запиті, не при build. next/font: 1) Zero layout shift — шрифти завантажуються на етапі build. 2) Self-hosted — Google Fonts без запитів до Google. 3) CSS size-adjust — автоматичний fallback без CLS. 4) Variable fonts підтримка. Використання: const inter = Inter({ subsets: ['latin'] }); <div className={inter.className}>." },
            { level: "middle", q: "Що таке middleware у Next.js? Де він виконується?", a: "Middleware — функція, що виконується ПЕРЕД кожним запитом на Edge Runtime (не Node.js). Файл: middleware.ts у корені проєкту. Можливості: 1) Redirect/rewrite URL. 2) Модифікація headers/cookies. 3) Authentication — перевірка токена перед доступом до сторінки. 4) A/B testing — redirect на різні варіанти. 5) Geo-routing — redirect за країною. Обмеження Edge Runtime: немає Node.js API (fs, child_process), обмежений набір npm пакетів, cold start < 1ms. Matcher — конфігурація шляхів: export const config = { matcher: ['/dashboard/:path*'] }. Middleware має бути легким — він виконується для кожного запиту." },
            { level: "middle", q: "Як реалізувати динамічні роути та catch-all сегменти?", a: "Динамічні роути: app/posts/[slug]/page.tsx — params.slug = значення з URL. Кілька параметрів: app/[category]/[id]/page.tsx. Catch-all: app/docs/[...slug]/page.tsx — slug = ['a', 'b', 'c'] для /docs/a/b/c. Optional catch-all: app/docs/[[...slug]]/page.tsx — також матчить /docs (slug = undefined). generateStaticParams() — SSG для динамічних роутів (заміна getStaticPaths): export async function generateStaticParams() { return posts.map(p => ({ slug: p.slug })); }. dynamicParams = false — 404 для невказаних params. Dynamic segments працюють і в Route Handlers: app/api/users/[id]/route.ts." },
            { level: "senior", q: "Поясни caching стратегії у Next.js App Router: full route cache, data cache, router cache.", a: "4 рівні кешування: 1) Request Memoization — дедуплікація однакових fetch у межах одного рендеру (React cache). 2) Data Cache — персистентне кешування fetch результатів на сервері. fetch(url, { cache: 'force-cache' }) (default) або { next: { revalidate: 60 } }. 3) Full Route Cache — кешування HTML та RSC payload для static routes на сервері. Інвалідується при revalidate або revalidatePath/revalidateTag. 4) Router Cache — клієнтський кеш RSC payload для навігації (prefetched routes). 30с для dynamic, 5хв для static. Інвалідація: revalidatePath(), revalidateTag(), router.refresh(). Складність кешування — одна з найбільших проблем App Router." },
            { level: "senior", q: "Що таке Partial Prerendering (PPR)? Як Suspense boundaries впливають на рендеринг?", a: "PPR (Next.js 14+, experimental) — комбінує static shell та dynamic holes в одному запиті. Static частина відправляється одразу (з CDN), dynamic частини стрімяться коли готові. Suspense boundaries визначають межі: все поза Suspense — static (prerendered at build), всередині Suspense — dynamic (rendered at request time). Приклад: статичний header/sidebar (instant) + динамічний user-specific content (streamed). Без PPR: сторінка або повністю static, або повністю dynamic. PPR дає best of both worlds — TTFB як у SSG, актуальність як у SSR. Вимагає правильне розміщення Suspense boundaries для оптимальної granularity." },
            { level: "senior", q: "Як оптимізувати Web Vitals (LCP, CLS, FID/INP) у Next.js додатку?", a: "LCP (Largest Contentful Paint): 1) next/image з priority для above-fold зображень. 2) Server Components — менше JS. 3) Streaming SSR — швидший TTFB. 4) Font optimization (next/font). 5) Preload critical resources. CLS (Cumulative Layout Shift): 1) Image dimensions (width/height або fill). 2) next/font з size-adjust. 3) Skeleton loading states у loading.tsx. 4) Статичні розміри для dynamic content. INP (Interaction to Next Paint): 1) Мінімізація client JS (Server Components). 2) useTransition для non-urgent updates. 3) Dynamic imports для важкого JS. 4) Web Workers для обчислень. Вимірювання: next/web-vitals, Lighthouse, CrUX, @next/bundle-analyzer." },
            { level: "senior", q: "Поясни streaming SSR. Як `Suspense` та `loading.tsx` впливають на TTFB?", a: "Streaming SSR — відправка HTML частинами (chunks) по мірі готовності, замість очікування повного рендеру. Покращує TTFB — перші байти відправляються одразу (shell). loading.tsx — автоматичний Suspense boundary для route segment. Генерує instant loading state, поки page.tsx рендериться. Процес: 1) Сервер відправляє HTML shell + loading fallbacks. 2) Компоненти всередині Suspense рендеряться асинхронно. 3) Готовий HTML стрімиться клієнту, замінює fallback. 4) React hydrate готові частини. Вкладені loading.tsx створюють granular streaming — різні частини сторінки з'являються незалежно. Transfer-Encoding: chunked. Кожен Suspense boundary — окремий chunk." },
            { level: "senior", q: "Як налаштувати Next.js для великого monorepo? Які є проблеми з turborepo?", a: "Monorepo setup: Turborepo або Nx для orchestration, pnpm workspaces для packages. Структура: apps/web (Next.js), apps/admin, packages/ui, packages/shared. next.config.js: transpilePackages для internal packages. Проблеми: 1) Build time — великий dependency graph. Turborepo remote caching допомагає (хешує inputs → кешує outputs). 2) TypeScript — project references, composite: true, paths mapping. 3) Shared configs — eslint, tsconfig, tailwind. 4) Version conflicts — singleton packages (react). 5) CI — affected filtering (turbo run build --filter=web...). 6) Docker — складні Dockerfiles з pruned dependencies. 7) Hot reload — symlinks можуть ламати watch mode." },
            { level: "senior", q: "Що таке Server Actions? Де вони виконуються і які є security considerations?", a: "Server Actions — async функції, що виконуються на сервері, викликаються з клієнта. Маркер: 'use server' (на рівні функції або файлу). Використання: form action={serverAction}, або виклик напряму з client component. Під капотом: Next.js створює POST ендпоінт, клієнт відправляє запит. Security considerations: 1) Валідація input — ЗАВЖДИ валідувати на сервері (zod). 2) Auth перевірка — не довіряти клієнту. 3) CSRF — Next.js додає automatic CSRF protection. 4) Closure variables — не захоплювати sensitive дані, вони серіалізуються. 5) Rate limiting. 6) Arguments encryption — Next.js шифрує серіалізовані closure values. Переваги: progressive enhancement (працює без JS), type-safe, менше boilerplate ніж API routes." },
        ],
    },
    "State Management": {
        icon: "🗂️",
        color: "#764abc",
        questions: [
            { level: "junior", q: "Що таке Redux? Поясни flux архітектуру: actions, reducers, store.", a: "Redux — передбачуваний state контейнер на основі Flux архітектури. Принципи: 1) Single source of truth — один store. 2) State is read-only — зміни тільки через actions. 3) Pure reducers — reducer(state, action) → newState без side effects. Flow: UI → dispatch(action) → reducer → new state → UI update. Action: { type: 'ADD_TODO', payload: {...} }. Reducer: switch по action.type, повертає НОВИЙ стан (immutable). Store: createStore(reducer), зберігає стан, надає getState(), dispatch(), subscribe(). Middleware (redux-thunk, redux-saga) — для async операцій між dispatch і reducer." },
            { level: "junior", q: "Що таке `useSelector` та `useDispatch`?", a: "useSelector(selectorFn) — hook для читання даних зі store. selector приймає весь state, повертає потрібну частину: const todos = useSelector(state => state.todos). Компонент ре-рендериться тільки якщо результат selector змінився (strict equality ===). Для derived data — використовувати createSelector (reselect) з мемоізацією. useDispatch() — повертає dispatch функцію для відправки actions: const dispatch = useDispatch(); dispatch(addTodo(text)). Стабільна посилка (не змінюється між рендерами). Обидва замінюють connect() HOC, який використовувався з класовими компонентами." },
            { level: "middle", q: "Що таке Redux Toolkit? Чим він кращий за vanilla Redux?", a: "Redux Toolkit (RTK) — офіційний рекомендований спосіб писати Redux. Переваги: 1) configureStore — автоматично додає middleware (thunk), DevTools, combines reducers. 2) createSlice — генерує action creators і action types з reducer функцій. Дозволяє мутабельний синтаксис (Immer під капотом). 3) createAsyncThunk — стандартизовані async actions з pending/fulfilled/rejected. 4) createEntityAdapter — нормалізація state для CRUD. 5) RTK Query — data fetching і caching. Менше boilerplate: vanilla Redux потребує окремих файлів для actions, types, reducers. RTK — все в одному slice." },
            { level: "middle", q: "Що таке RTK Query? Як він відрізняється від React Query?", a: "RTK Query — data fetching та caching бібліотека, вбудована в Redux Toolkit. createApi визначає endpoints, автоматично генерує hooks (useGetUsersQuery). Відмінності від React Query: RTK Query: інтегрований у Redux store, endpoints визначаються централізовано, code generation з OpenAPI, automatic re-fetching з tags (invalidation). React Query (TanStack Query): незалежний від state manager, більш гнучкий (будь-який async function), stale-while-revalidate за замовчуванням, parallel/dependent queries простіші, більша community, працює з будь-яким фреймворком. Вибір: RTK Query якщо вже є Redux, React Query — для нових проєктів або без Redux." },
            { level: "middle", q: "Що таке Zustand? Порівняй з Redux.", a: "Zustand — легковагий state manager з мінімальним API. Створення: const useStore = create((set) => ({ count: 0, inc: () => set(state => ({ count: state.count + 1 })) })). Використання: const count = useStore(state => state.count). Порівняння з Redux: 1) Менше boilerplate — немає actions/reducers/dispatch. 2) Не потрібен Provider — store доступний де завгодно. 3) Менший bundle (< 1KB). 4) Selector за замовчуванням — точкові ре-рендери. 5) Мутабельний API (Immer опціонально). Redux переваги: DevTools, middleware ecosystem, RTK Query, більше структури для великих команд. Zustand — для малих/середніх проєктів, Redux — для великих enterprise додатків." },
            { level: "middle", q: "Що таке Jotai/Recoil? Що таке атомарний state management?", a: "Атомарний state management — підхід, де стан складається з незалежних атомів (маленьких шматків state). Компоненти підписуються тільки на потрібні атоми → мінімальні ре-рендери. Jotai: const countAtom = atom(0); const [count, setCount] = useAtom(countAtom). Derived atoms: const doubleAtom = atom(get => get(countAtom) * 2). Async atoms з підтримкою Suspense. Recoil (Meta): atoms + selectors, atom effects, snapshot. Переваги: 1) Bottom-up — починаєш з маленьких атомів, комбінуєш. 2) Точкові ре-рендери без selector оптимізацій. 3) React-native API (як useState). 4) Code splitting friendly. Jotai — простіший і менший за Recoil." },
            { level: "middle", q: "Поясни імутабельність у state management. Навіщо вона важлива?", a: "Імутабельність — стан ніколи не мутується напряму, створюється новий об'єкт: НЕ state.items.push(item), А { ...state, items: [...state.items, item] }. Навіщо: 1) Передбачуваність — стан змінюється тільки через визначені actions. 2) Change detection — React порівнює посилання (===), нова посилка = зміна. Мутація того ж об'єкта не буде помічена. 3) Time-travel debugging — зберігання попередніх станів (Redux DevTools). 4) Undo/Redo. 5) Безпечний sharing між компонентами. Інструменти: spread operator, Array methods (map, filter), Immer (мутабельний синтаксис, імутабельний результат). Redux Toolkit використовує Immer автоматично." },
            { level: "senior", q: "Як ти обираєш між локальним, сервер і глобальним state? Дай чіткі criteria.", a: "Criteria: 1) LOCAL state (useState/useReducer) — дані використовуються тільки в одному компоненті або його безпосередніх дітях. Форми, UI toggles, анімації. 2) SERVER state (React Query/SWR) — дані з API. Характеристики: може бути stale, потребує sync з сервером, кешування, refetching, optimistic updates. Більшість даних у типовому SPA — server state. 3) GLOBAL CLIENT state (Zustand/Redux) — дані, які потрібні багатьом компонентам І не приходять з сервера. Тема, auth status, sidebar state, wizard state. Правило: якщо можна не робити глобальним — не роби. URL — теж state (search params, route params). Server state ≠ global state — не зберігай API дані в Redux." },
            { level: "senior", q: "Що таке optimistic updates? Як реалізувати з rollback?", a: "Optimistic update — оновлення UI одразу до відповіді сервера, припускаючи успіх. Покращує perceived performance. Реалізація з rollback: 1) Зберегти попередній стан. 2) Оновити UI оптимістично. 3) Надіслати запит на сервер. 4) При помилці — rollback до збереженого стану. React Query: useMutation({ mutationFn: updateTodo, onMutate: async (newTodo) => { await queryClient.cancelQueries(['todos']); const previous = queryClient.getQueryData(['todos']); queryClient.setQueryData(['todos'], old => [...old, newTodo]); return { previous }; }, onError: (err, vars, context) => queryClient.setQueryData(['todos'], context.previous), onSettled: () => queryClient.invalidateQueries(['todos']) }). Важливо: показувати subtle feedback (не повний loader, а pending стан)." },
            { level: "senior", q: "Поясни проблему N+1 запитів на фронтенді. Як React Query вирішує це?", a: "N+1 проблема: список з N елементів, кожен робить окремий запит за додатковими даними. Приклад: список 100 постів, кожен Post компонент робить useQuery для автора → 1 + 100 запитів. React Query рішення: 1) Запитувати всі дані одним запитом (API endpoint з includes/populate). 2) Deduplication — однакові query keys автоматично дедуплікуються (1 запит замість N однакових). 3) Batch endpoints — API, що приймає масив ID. 4) Initial data — передавати дані з батьківського запиту: useQuery({ queryKey: ['author', post.authorId], initialData: post.author }). 5) GraphQL вирішує через один запит з nested fields. 6) DataLoader pattern — batch + deduplicate на сервері." },
            { level: "senior", q: "Як нормалізувати state у Redux? Що таке entity adapter?", a: "Нормалізація — зберігання даних як словник (byId) + масив ID (allIds), уникаючи дублювання і вкладеності. Замість: [{ id: 1, author: { id: 5, name: 'John' } }] → users: { ids: [5], entities: { 5: { id: 5, name: 'John' } } }, posts: { ids: [1], entities: { 1: { id: 1, authorId: 5 } } }. createEntityAdapter (RTK): const adapter = createEntityAdapter<User>(); Надає: getInitialState(), addOne, addMany, updateOne, removeOne, setAll. Selectors: adapter.getSelectors() → selectAll, selectById, selectIds. Переваги: O(1) lookup за ID, немає дублювання, простіші оновлення, менше ре-рендерів (зміна одного entity не впливає на інші)." },
            { level: "senior", q: "Як ти вирішуєш проблему надмірних ре-рендерів при використанні Context?", a: "Проблема: зміна будь-якої частини context value → ре-рендер ВСІХ споживачів. Рішення: 1) Розділити context — окремий context для рідко змінюваних даних (theme) і часто змінюваних (state). 2) Мемоізувати value: const value = useMemo(() => ({ theme, toggleTheme }), [theme]). 3) Розділити state і dispatch contexts — dispatch ніколи не змінюється, компоненти що тільки dispatch-ать не ре-рендеряться. 4) use-context-selector — бібліотека для вибіркової підписки. 5) Замінити Context на Zustand/Jotai — вони мають вбудований selector механізм. 6) React.memo на споживачах — не допомагає з Context, але обмежує каскад. Найкращий підхід: Zustand для частих оновлень, Context — тільки для рідко змінюваних." },
        ],
    },
    "Performance": {
        icon: "🚀",
        color: "#00c896",
        questions: [
            { level: "junior", q: "Що таке Core Web Vitals? Поясни LCP, CLS, FID/INP.", a: "Core Web Vitals — метрики Google для оцінки user experience. LCP (Largest Contentful Paint) — час рендеру найбільшого видимого елемента (зображення, текстовий блок). Ціль: < 2.5с. CLS (Cumulative Layout Shift) — сума непередбачуваних зсувів layout (зображення без розмірів, динамічний контент, шрифти). Ціль: < 0.1. FID (First Input Delay) — замінений на INP (Interaction to Next Paint) — час від взаємодії користувача до візуальної відповіді (обробка всіх interactions, не тільки першої). Ціль: < 200ms. Вимірювання: Lighthouse, PageSpeed Insights, CrUX (реальні користувачі), web-vitals бібліотека." },
            { level: "middle", q: "Що таке code splitting? Як реалізувати в React/Next.js?", a: "Code splitting — розділення bundle на менші chunks, які завантажуються за потребою. Зменшує initial load. React: React.lazy(() => import('./Component')) + Suspense. Dynamic import: const module = await import('./heavy-lib'). Next.js: 1) Автоматичний — кожна сторінка = окремий chunk. 2) next/dynamic — dynamic(() => import('./Chart'), { loading: () => <Spinner /> }). 3) ssr: false для client-only компонентів. Стратегії: route-based (найефективніший), component-based (модалки, tabs), library-based (lodash → lodash-es + tree shaking). Webpack magic comments: /* webpackChunkName: 'chart' */ для іменованих chunks." },
            { level: "middle", q: "Поясни lazy loading для зображень та компонентів.", a: "Lazy loading — відкладене завантаження ресурсів до моменту потреби. Зображення: 1) loading='lazy' (native) — браузер завантажує коли зображення близько до viewport. 2) IntersectionObserver — кастомна імплементація з placeholder. 3) next/image — lazy за замовчуванням + blur placeholder. Не використовувати lazy для above-fold зображень (priority). Компоненти: React.lazy(() => import('./Chart')) + Suspense. Стратегії: on viewport (IntersectionObserver), on interaction (клік на tab), on idle (requestIdleCallback). Бібліотеки: react-lazyload, react-intersection-observer. Важливо: CLS — завжди задавати розміри placeholder." },
            { level: "middle", q: "Що таке bundle analysis? Які інструменти використовуєш?", a: "Bundle analysis — аналіз розміру та складу JavaScript bundle для виявлення проблем. Інструменти: 1) webpack-bundle-analyzer — інтерактивна treemap, показує розміри модулів. 2) @next/bundle-analyzer — обгортка для Next.js. 3) source-map-explorer — аналіз по source maps. 4) bundlephobia.com — перевірка розміру npm пакетів. 5) import cost (VS Code extension) — показує розмір імпорту в реальному часі. Що шукати: великі залежності (moment.js → day.js), дублювання бібліотек, непотрібні polyfills, barrel files (index.ts з re-exports). Оптимізації: tree shaking, dynamic imports, lighter alternatives, sideEffects: false." },
            { level: "middle", q: "Поясни debounce vs throttle. Напиши реалізацію.", a: "Debounce — виконує функцію після паузи N ms. Кожен новий виклик скидає таймер. Для: пошук при введенні, resize, auto-save. function debounce(fn, delay) { let timer; return (...args) => { clearTimeout(timer); timer = setTimeout(() => fn(...args), delay); }; }. Throttle — виконує функцію не частіше ніж раз у N ms. Гарантує виконання з інтервалом. Для: scroll, mousemove, resize. function throttle(fn, limit) { let inThrottle; return (...args) => { if (!inThrottle) { fn(...args); inThrottle = true; setTimeout(() => inThrottle = false, limit); } }; }. Debounce — \"почекай поки зупиниться\", Throttle — \"не частіше ніж N ms\". У React: useDeferredValue як альтернатива debounce." },
            { level: "middle", q: "Що таке virtualization (windowing)? Коли і як використовувати react-window?", a: "Virtualization — рендеринг тільки видимих елементів списку + буфер. Замість 10,000 DOM-елементів — ~20-30 видимих. Різко зменшує DOM nodes, memory та initial render time. react-window: FixedSizeList — елементи однакового розміру (найшвидший). VariableSizeList — різні розміри (потрібен itemSize callback). FixedSizeGrid/VariableSizeGrid — 2D. Використання: import { FixedSizeList } from 'react-window'; <FixedSizeList height={400} itemCount={10000} itemSize={35} width={300}>{({ index, style }) => <div style={style}>{items[index]}</div>}</FixedSizeList>. Коли: > 100-200 елементів, складні елементи списку. react-virtuoso — альтернатива з dynamic heights, grouped lists." },
            { level: "senior", q: "Як виміряти та оптимізувати React rendering performance? Які інструменти?", a: "Вимірювання: 1) React DevTools Profiler — flame chart ре-рендерів, причини рендеру, тривалість. 2) React.Profiler component — programmatic profiling. 3) Chrome Performance tab — flame chart, paint, layout. 4) why-did-you-render — логує непотрібні ре-рендери. 5) React DevTools Highlight Updates. Оптимізація: 1) React.memo для чистих компонентів. 2) useMemo/useCallback для стабільних посилань. 3) Правильна granularity компонентів — виносити змінювану частину. 4) Virtualization для списків. 5) Code splitting. 6) useTransition для non-urgent updates. 7) Уникати anonymous objects/functions у props. 8) Key prop — стабільні keys. 9) Context splitting." },
            { level: "senior", q: "Поясни HTTP/2 та HTTP/3. Як вони впливають на завантаження ресурсів?", a: "HTTP/1.1: один запит per connection, head-of-line blocking, 6 parallel connections per domain. HTTP/2: 1) Multiplexing — багато запитів через одне TCP з'єднання. 2) Header compression (HPACK). 3) Server Push — сервер відправляє ресурси до запиту. 4) Stream prioritization. Вплив: не потрібен domain sharding, менше з'єднань, sprite sheets та bundling менш критичні (але все ще корисні через compression). HTTP/3: 1) QUIC протокол (UDP замість TCP). 2) Немає head-of-line blocking на transport рівні. 3) Швидший handshake (0-RTT). 4) Кращий для нестабільних з'єднань (mobile). 5) Connection migration — зміна мережі без розриву. Для фронтенду: менші bundles все ще краще, але багато малих файлів вже не так страшно." },
            { level: "senior", q: "Що таке service worker та workbox? Як реалізувати offline-first?", a: "Service Worker — JS скрипт, що працює у фоновому потоці між браузером і мережею. Перехоплює fetch запити, дозволяє кешувати ресурси та працювати offline. Lifecycle: install → activate → fetch. Workbox (Google) — бібліотека для спрощення SW: 1) Precaching — кешування ресурсів при install (app shell). 2) Runtime caching стратегії: CacheFirst (static assets), NetworkFirst (API), StaleWhileRevalidate (часто оновлюваний контент), NetworkOnly, CacheOnly. 3) Background sync — відправка запитів коли мережа повернеться. Offline-first: 1) App shell кешується при install. 2) Дані кешуються з StaleWhileRevalidate. 3) IndexedDB для structured data. 4) Background sync для мутацій. next-pwa — інтеграція Workbox з Next.js." },
            { level: "senior", q: "Поясни стратегії кешування: Cache-Control, ETag, stale-while-revalidate.", a: "Cache-Control header: max-age=3600 (кешувати 1 годину), no-cache (завжди перевіряти з сервером), no-store (ніколи не кешувати), public/private, immutable (ніколи не revalidate). ETag — хеш контенту. Браузер надсилає If-None-Match з ETag, сервер повертає 304 Not Modified якщо не змінилось (без body). Last-Modified/If-Modified-Since — аналогічно за датою. stale-while-revalidate: Cache-Control: max-age=60, stale-while-revalidate=3600 — 60с свіжий, потім 3600с відправляє stale і оновлює у фоні. Стратегія: JS/CSS з hash — immutable, max-age=31536000. HTML — no-cache або short max-age. API — stale-while-revalidate для нечутливих даних. Images — long max-age." },
            { level: "senior", q: "Що таке resource hints: preload, prefetch, preconnect, dns-prefetch? Коли що використовувати?", a: "preload — завантажити ресурс ЗАРАЗ (high priority). Для critical ресурсів поточної сторінки: шрифти, hero image, critical CSS/JS. <link rel='preload' href='font.woff2' as='font' crossorigin>. prefetch — завантажити у вільний час для МАЙБУТНЬОЇ навігації. Low priority. Для ресурсів наступних сторінок. <link rel='prefetch' href='/next-page.js'>. preconnect — встановити з'єднання заздалегідь (DNS + TCP + TLS). Для third-party origins: CDN, API, analytics. <link rel='preconnect' href='https://api.example.com'>. dns-prefetch — тільки DNS lookup (легший за preconnect). Для менш критичних third-party. Fallback для preconnect. Next.js: Image автоматично додає preconnect, next/font — preload." },
            { level: "senior", q: "Як ти би оптимізував Time to Interactive для великого SPA?", a: "TTI — час, коли сторінка повністю інтерактивна (main thread вільний 5с). Стратегії: 1) Зменшити JS: code splitting (route-based), tree shaking, lighter alternatives (lodash → lodash-es, moment → dayjs). 2) Defer non-critical JS: dynamic imports, requestIdleCallback, defer/async script. 3) SSR/SSG — HTML одразу, hydration у фоні. Selective/partial hydration (React Server Components). 4) Streaming SSR — інтерактивність по частинах. 5) Web Workers — важкі обчислення поза main thread. 6) Third-party scripts — async load, facade pattern (YouTube lite). 7) Preload critical resources. 8) Optimize long tasks — розбити на менші (yield to main thread). 9) Service Worker — кешування для repeat visits. 10) Performance budget — автоматичний контроль розміру bundle в CI." },
        ],
    },
    "Testing": {
        icon: "🧪",
        color: "#c0392b",
        questions: [
            { level: "junior", q: "Що таке unit, integration та e2e тести? Яка різниця?", a: "Unit тести — тестування ізольованої одиниці коду (функція, компонент) з мокуванням залежностей. Швидкі, багато, дешеві. Integration тести — тестування взаємодії кількох модулів разом (компонент з API, форма з валідацією). Без мокування або з мінімальним. E2E тести — тестування повного user flow через браузер (реєстрація → логін → дія). Найповільніші, найдорожчі, найближчі до реального використання. Інструменти: Unit/Integration — Jest + React Testing Library. E2E — Playwright, Cypress. Баланс: багато integration, достатньо unit, мінімум e2e для критичних шляхів." },
            { level: "junior", q: "Що таке Jest? Як написати простий тест?", a: "Jest — JavaScript testing framework від Meta. Включає: test runner, assertion library, mocking, coverage. Приклад: describe('sum', () => { test('adds 1 + 2 to equal 3', () => { expect(sum(1, 2)).toBe(3); }); }). Основні matchers: toBe (===), toEqual (deep), toBeTruthy, toContain, toThrow, toHaveBeenCalledWith. Async: await expect(fetchData()).resolves.toBe('data'). Setup/teardown: beforeEach, afterEach, beforeAll, afterAll. Mocking: jest.fn(), jest.mock('./module'), jest.spyOn. Coverage: jest --coverage → html report. Конфігурація: jest.config.ts або package.json." },
            { level: "middle", q: "Що таке React Testing Library? Яка філософія тестування?", a: "React Testing Library (RTL) — бібліотека для тестування React компонентів з фокусом на поведінку, а не implementation details. Філософія: \"The more your tests resemble the way your software is used, the more confidence they give you.\" Пріоритет queries: getByRole > getByLabelText > getByPlaceholderText > getByText > getByTestId. НЕ тестувати: state, props, instance methods. Тестувати: що бачить користувач, взаємодію. API: render(<Comp />), screen.getByRole('button'), fireEvent.click() або userEvent.click() (реалістичніший). findBy* — для async. waitFor — очікування змін. Антипатерни: тестування implementation details, snapshot testing як єдина стратегія." },
            { level: "middle", q: "Поясни мокування (mocking). Коли мокувати, а коли ні?", a: "Мокування — заміна реальної залежності на контрольовану версію. Jest: jest.fn() — mock функція, jest.mock('./api') — mock модуля, jest.spyOn(obj, 'method') — spy з можливістю підміни. Мокувати: 1) Зовнішні сервіси (API calls, БД). 2) Таймери (jest.useFakeTimers). 3) Випадкові/часові значення (Date.now, Math.random). 4) Важкі залежності (file system). НЕ мокувати: 1) Модуль, який тестуєш. 2) Прості утиліти без side effects. 3) Все підряд — надмірне мокування робить тести крихкими і не виявляє реальних багів. MSW (Mock Service Worker) — кращий підхід для API: мокування на мережевому рівні, а не на рівні fetch." },
            { level: "middle", q: "Що таке snapshot testing? Плюси та мінуси?", a: "Snapshot testing — зберігання серіалізованого output (HTML, JSON) і порівняння при наступних запусках. Jest: expect(component).toMatchSnapshot() або toMatchInlineSnapshot(). Плюси: 1) Швидке виявлення непередбачуваних змін UI. 2) Легко додати (один рядок). 3) Документування очікуваного output. Мінуси: 1) Великі snapshots — ніхто не ревʼювить, просто оновлюють (jest --updateSnapshot). 2) Крихкі — будь-яка зміна ламає, навіть правильна. 3) False confidence — проходять тести не означає правильну роботу. 4) Merge conflicts. Рекомендація: inline snapshots для маленьких outputs, не використовувати для великих компонентів, поєднувати з behavior tests." },
            { level: "middle", q: "Що таке Cypress vs Playwright? Яку різницю ти бачиш?", a: "Cypress: 1) Працює всередині браузера (JavaScript). 2) Тільки Chromium повністю, Firefox частково, Safari — ні. 3) Чудовий DX — time-travel debugging, GUI runner. 4) Один tab — не підтримує multi-tab сценарії. 5) Component testing вбудований. Playwright (Microsoft): 1) Зовнішній контроль через CDP/protocol. 2) Chromium, Firefox, WebKit (Safari). 3) Multi-tab, multi-browser, multi-context. 4) Auto-waiting — розумніше очікування елементів. 5) Codegen — запис дій → генерація тесту. 6) Паралельне виконання з коробки. Рекомендація: Playwright для нових проєктів — кращий cross-browser, швидший, потужніший API. Cypress — якщо DX важливіший за cross-browser." },
            { level: "senior", q: "Що таке Testing Trophy vs Testing Pyramid? Яку стратегію обираєш?", a: "Testing Pyramid (традиційний): широка база unit tests → менше integration → мінімум e2e. Оптимізує швидкість та cost. Testing Trophy (Kent C. Dodds): маленька база static (TypeScript/ESLint) → мало unit → БАГАТО integration → мало e2e. Аргумент: integration тести дають найбільший confidence per dollar. Unit тести часто тестують implementation details. Мій підхід: Static analysis (TypeScript strict, ESLint) — безкоштовний confidence. Integration (RTL) — основна маса тестів, компоненти з реальними залежностями. Unit — для складної бізнес-логіки, utilities, pure functions. E2E (Playwright) — критичні user flows (auth, checkout, payment). Coverage: не гнатися за 100%, фокус на критичних шляхах." },
            { level: "senior", q: "Як тестувати async компоненти та custom hooks?", a: "Async компоненти (data fetching): 1) MSW для мокування API на мережевому рівні. 2) findBy* queries (повертають Promise): const user = await screen.findByText('John'). 3) waitFor — очікування умови: await waitFor(() => expect(screen.getByText('loaded')).toBeInTheDocument()). 4) act() — обгортка для state updates. Custom hooks: @testing-library/react → renderHook: const { result } = renderHook(() => useCounter()); act(() => result.current.increment()); expect(result.current.count).toBe(1). Async hooks: const { result } = renderHook(() => useFetch('/api')); await waitFor(() => expect(result.current.data).toBeDefined()). Wrapper для providers: renderHook(hook, { wrapper: AllProviders })." },
            { level: "senior", q: "Що таке Visual Regression Testing? Які інструменти є?", a: "Visual Regression Testing — порівняння скріншотів UI з еталонними для виявлення візуальних змін. Процес: 1) Зробити baseline screenshots. 2) При змінах — нові screenshots. 3) Pixel-by-pixel порівняння. 4) Highlight differences. Інструменти: 1) Playwright built-in: await expect(page).toHaveScreenshot(). 2) Percy (BrowserStack) — cloud-based, cross-browser, CI інтеграція. 3) Chromatic — від Storybook team, component-level snapshots. 4) BackstopJS — open-source, Docker-based. 5) Loki — для Storybook. Проблеми: 1) Flaky — anti-aliasing, шрифти, animations (потрібно disable). 2) Threshold — допустима різниця в пікселях. 3) Maintenance — часте оновлення baselines. Рекомендація: Chromatic для Storybook проєктів, Playwright screenshots для e2e." },
            { level: "senior", q: "Як організувати тестування у великому проєкті? CI pipeline, coverage thresholds.", a: "Структура: тести поруч з кодом (__tests__/ або .test.ts). Конвенції: unit — .test.ts, integration — .integration.test.ts, e2e — .e2e.ts. CI Pipeline: 1) Lint + Type check (fastest). 2) Unit + Integration tests (parallel). 3) Build. 4) E2E tests (slowest, after deploy to staging). 5) Visual regression. Coverage: не 100% — diminishing returns. Thresholds: 70-80% для statements/branches на критичних модулях. Enforce: jest --coverageThreshold. Pre-commit hooks: lint-staged + husky для швидких перевірок. Parallelization: jest --shard, playwright --workers. Test isolation: кожен тест незалежний, cleanup afterEach. Flaky tests: retry policy (2-3 спроби), quarantine flaky tests, fix root cause." },
        ],
    },
    "Node.js": {
        icon: "🟩",
        color: "#68a063",
        questions: [
            { level: "junior", q: "Що таке Node.js? Чому він non-blocking та single-threaded?", a: "Node.js — JavaScript runtime побудований на V8 engine (Chrome). Single-threaded — один main thread виконує JS код. Non-blocking — I/O операції (файли, мережа, БД) делегуються OS/libuv thread pool і не блокують main thread. Коли I/O завершується — callback додається в event queue. Це дозволяє обробляти тисячі одночасних з'єднань одним процесом (на відміну від thread-per-request моделі). Підходить для: I/O-intensive задач (API сервери, real-time, streaming). Не підходить для: CPU-intensive (блокує main thread, рішення: worker_threads). npm — найбільший пакетний менеджер у світі." },
            { level: "junior", q: "Що таке Event Loop у Node.js? Чим відрізняється від браузерного?", a: "Event Loop у Node.js має фази (відмінність від браузерного): 1) Timers — setTimeout/setInterval callbacks. 2) Pending callbacks — I/O callbacks відкладені з попередньої ітерації. 3) Idle/prepare — внутрішнє. 4) Poll — нові I/O events, виконує callbacks. 5) Check — setImmediate callbacks. 6) Close — close events (socket.on('close')). Між фазами — виконуються ВСІ microtasks (process.nextTick → Promise.then). Відмінності від браузера: 1) process.nextTick (вищий пріоритет за Promise). 2) setImmediate (після poll phase, немає в браузері). 3) Фази замість простої task/microtask моделі. 4) Немає requestAnimationFrame/requestIdleCallback." },
            { level: "junior", q: "Що таке npm та package.json? Поясни dependencies vs devDependencies.", a: "npm — пакетний менеджер Node.js (Node Package Manager). package.json — маніфест проєкту: name, version, scripts, dependencies. dependencies — пакети, потрібні в production (express, react). Встановлюються завжди. devDependencies — пакети тільки для розробки (jest, typescript, eslint). Не встановлюються при npm install --production. peerDependencies — вимога до хост-проєкту (плагіни). Версіонування (semver): ^1.2.3 — minor updates (1.x.x), ~1.2.3 — patch updates (1.2.x), 1.2.3 — exact. package-lock.json — фіксує точні версії всіх залежностей (завжди коммітити). Альтернативи: yarn, pnpm (ефективніший — symlinks, strict)." },
            { level: "junior", q: "Як читати файли в Node.js? Sync vs Async?", a: "Модуль fs: Sync: const data = fs.readFileSync('file.txt', 'utf8') — блокує event loop до завершення. Використовувати тільки при старті (конфігурація). Async (callback): fs.readFile('file.txt', 'utf8', (err, data) => {}). Async (Promise): const data = await fs.promises.readFile('file.txt', 'utf8'). Рекомендація: завжди використовувати async (promises) в серверному коді, sync тільки в CLI скриптах або на старті. Для великих файлів — streams: const stream = fs.createReadStream('file.txt') — читає частинами, не завантажує весь файл у пам'ять. Encoding: без 'utf8' повертає Buffer." },
            { level: "middle", q: "Що таке streams у Node.js? Поясни типи: Readable, Writable, Transform, Duplex.", a: "Streams — абстракція для роботи з потоковими даними (читання/запис частинами). Не завантажують весь файл у пам'ять. Readable — джерело даних: fs.createReadStream, http request, process.stdin. Events: data, end, error. Writable — приймач даних: fs.createWriteStream, http response, process.stdout. Methods: write(), end(). Duplex — і Readable, і Writable (незалежно): TCP socket, zlib. Transform — Duplex, де output залежить від input: zlib.createGzip(), crypto.createCipher(). Pipe: readable.pipe(transform).pipe(writable). Pipeline (рекомендований): pipeline(source, transform, dest, callback) — автоматичне error handling та cleanup." },
            { level: "middle", q: "Що таке EventEmitter? Як він реалізований?", a: "EventEmitter — клас для реалізації observer pattern у Node.js. Основа багатьох Node.js API (streams, http, process). API: emitter.on(event, listener) — підписка. emitter.emit(event, ...args) — виклик всіх listeners. emitter.once(event, listener) — одноразова підписка. emitter.removeListener(event, listener) — відписка. emitter.removeAllListeners(). Реалізація: внутрішньо зберігає Map<eventName, listener[]>. emit() ітерує по масиву listeners і викликає їх синхронно. Використання: custom events у класах (extends EventEmitter), pub/sub pattern, decoupling модулів. Увага: memory leak warning при > 10 listeners (emitter.setMaxListeners(n))." },
            { level: "middle", q: "Поясни cluster та worker_threads. Яка різниця?", a: "Cluster — створює кілька процесів (child processes), кожен з власним V8 instance та пам'яттю. Master процес розподіляє вхідні з'єднання (round-robin). Використання: масштабування HTTP серверів на всі CPU ядра. IPC для комунікації між процесами. worker_threads — створює threads в одному процесі. Діляться пам'яттю через SharedArrayBuffer. Легші за процеси. Використання: CPU-intensive задачі (парсинг, обчислення, crypto). Різниця: Cluster — окремі процеси, ізольована пам'ять, для I/O scaling. Workers — threads, shared memory можливий, для CPU tasks. PM2 — production process manager, автоматично cluster mode." },
            { level: "middle", q: "Що таке middleware у Express? Як побудований pipeline?", a: "Middleware — функція (req, res, next) => {}, що має доступ до request, response і next function. Pipeline: middleware виконуються послідовно в порядку визначення. next() — передає контроль наступному middleware. Без next() — відповідь зависне. Типи: 1) Application-level: app.use(cors()). 2) Router-level: router.use(auth). 3) Error-handling: (err, req, res, next) — 4 параметри. 4) Built-in: express.json(), express.static(). 5) Third-party: cors, helmet, morgan. Порядок важливий: logger → cors → auth → routes → error handler. Middleware може: модифікувати req/res, завершити request (res.send), передати далі (next()), передати помилку (next(error))." },
            { level: "middle", q: "Як обробляти помилки в Express? Поясни error middleware.", a: "Error middleware — функція з 4 параметрами: (err, req, res, next). Визначається ПІСЛЯ всіх routes. Виклик: next(error) з будь-якого middleware або throw в async handler. Проблема: Express не ловить rejected promises (до Express 5). Рішення: wrapper: const asyncHandler = fn => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next). Express 5 — автоматично ловить async errors. Структура: 1) Operational errors (404, validation) — відповідь клієнту з деталями. 2) Programming errors (TypeError) — generic 500, логування. Централізований error handler: логування (winston/pino), форматування відповіді, різні формати для dev/prod." },
            { level: "middle", q: "Що таке libuv? Яку роль він відіграє в Node.js?", a: "libuv — C бібліотека, що забезпечує асинхронний I/O для Node.js. Крос-платформна (Windows, Linux, macOS). Роль: 1) Event Loop — реалізація циклу подій з фазами. 2) Thread Pool (4 threads за замовчуванням, UV_THREADPOOL_SIZE) — для операцій, що не мають async OS API: fs operations, DNS lookup (dns.lookup), crypto, zlib. 3) Async I/O — мережеві операції через OS mechanisms: epoll (Linux), kqueue (macOS), IOCP (Windows). 4) Таймери — setTimeout, setInterval. 5) Child processes. Важливо: мережеві запити (http, tcp) НЕ використовують thread pool — вони async на рівні OS. Файлові операції — використовують thread pool. Збільшення UV_THREADPOOL_SIZE допомагає при багатьох паралельних fs/dns операціях." },
            { level: "senior", q: "Поясни backpressure у streams. Як його правильно обробляти?", a: "Backpressure — ситуація, коли Writable stream не встигає обробляти дані від Readable stream. Writable буферизує в пам'яті → memory overflow. Механізм: writable.write(chunk) повертає false коли internal buffer повний (highWaterMark). Readable має призупинити відправку. Правильна обробка: 1) pipe()/pipeline() — автоматичний backpressure handling. readable.pipe(writable) автоматично pause/resume readable. 2) Manual: if (!writable.write(chunk)) { readable.pause(); writable.once('drain', () => readable.resume()); }. pipeline(src, dst, callback) — рекомендований метод: автоматичний error handling, cleanup, backpressure. Без обробки backpressure — memory leaks, OOM crashes." },
            { level: "senior", q: "Що таке `child_process`? Коли використовувати `spawn` vs `exec` vs `fork`?", a: "child_process — модуль для запуску зовнішніх процесів. exec(command, callback) — запускає shell команду, буферизує весь output (stdout/stderr). Для коротких команд з невеликим output. Ліміт buffer (200KB default). spawn(command, args) — запускає процес, повертає stream (stdout/stderr як streams). Для довготривалих процесів або великого output (відео, логи). Немає ліміту. fork(modulePath) — спеціальний spawn для Node.js скриптів. Створює IPC channel для комунікації (process.send/process.on('message')). Для CPU-intensive задачі в окремому Node процесі. execFile — як exec, але без shell (безпечніший). Завжди: sanitize input для exec (command injection), prefer spawn over exec для безпеки." },
            { level: "senior", q: "Як зробити Node.js сервер production-ready? Graceful shutdown, health checks, memory management.", a: "Graceful shutdown: process.on('SIGTERM', async () => { server.close(); await closeDB(); process.exit(0); }). Не приймати нові з'єднання, завершити поточні, закрити ресурси. Timeout для примусового завершення. Health checks: /health endpoint — readiness (може приймати трафік) та liveness (процес живий). Перевірка: DB connection, memory usage, event loop lag. Memory: --max-old-space-size, моніторинг process.memoryUsage(), утримання heap < 1.5GB. Додатково: 1) PM2 / Docker restart policy. 2) Structured logging (pino/winston). 3) Error handling — unhandledRejection, uncaughtException. 4) Rate limiting. 5) Helmet для HTTP headers. 6) Metrics (Prometheus). 7) Cluster mode або horizontal scaling." },
            { level: "senior", q: "Поясни memory model Node.js: V8 heap, Old Space, New Space, Large Object Space.", a: "V8 Heap складається з: 1) New Space (Young Generation) — маленький (1-8MB), для короткоживучих об'єктів. Два semi-spaces (From/To). Scavenge GC — копіює живі об'єкти з From в To, перемикає. Об'єкти, що пережили 2 scavenge → Old Space. 2) Old Space (Old Generation) — великий, довгоживучі об'єкти. Mark-Sweep-Compact GC — повільніший, рідший. 3) Large Object Space — об'єкти > 512KB, не переміщуються (не compacted). 4) Code Space — скомпільований JIT код. 5) Map Space — hidden classes (shapes). Поза Heap: Buffer (C++ heap), зовнішня пам'ять. process.memoryUsage(): rss (повна), heapTotal (виділена V8), heapUsed (зайнята), external (C++ objects), arrayBuffers." },
            { level: "senior", q: "Як діагностувати memory leak у Node.js додатку?", a: "Ознаки: RSS постійно зростає, не повертається після GC, OOM crashes. Діагностика: 1) process.memoryUsage() — логувати periodically, графіки heapUsed. 2) --inspect + Chrome DevTools Memory tab: Heap Snapshot — порівняння двох snapshots (comparison view показує leaked objects). Allocation Timeline — де створюються об'єкти. 3) node --heap-prof — запис heap profile. 4) clinic.js (npm) — flame graphs, memory analysis. 5) heapdump (npm) — snapshot у production через signal. Часті причини: 1) Event listeners без removeListener. 2) Global caches без eviction (Map що росте). 3) Closure що тримає великий scope. 4) Незакриті streams/connections. 5) Circular references з timers. Рішення: WeakRef/WeakMap, LRU cache, proper cleanup." },
            { level: "senior", q: "Що таке AsyncLocalStorage? Для чого використовується в production?", a: "AsyncLocalStorage (async_hooks module) — контекст, що автоматично передається через async ланцюжок без явної передачі. Аналог ThreadLocal у Java, але для async context. API: const als = new AsyncLocalStorage(); als.run(store, () => { /* весь async код має доступ до store */ }); als.getStore() — повертає store з поточного контексту. Production використання: 1) Request-scoped logging — correlation ID через всі логи одного запиту без передачі через аргументи. 2) User context — поточний user у будь-якому шарі (service, repository). 3) Transaction management — DB transaction доступна в усіх операціях. 4) Tracing — distributed tracing context (OpenTelemetry використовує ALS). Performance: мінімальний overhead, production-ready з Node.js 16+." },
        ],
    },
    "NestJS": {
        icon: "🐈",
        color: "#e0234e",
        questions: [
            { level: "junior", q: "Що таке NestJS? Яка архітектура лежить в основі?", a: "NestJS — прогресивний Node.js фреймворк для побудови ефективних серверних додатків. Побудований на TypeScript, натхненний Angular. Архітектура: модульна, з Dependency Injection, декораторами, чітким розділенням відповідальності. Під капотом: Express (за замовчуванням) або Fastify. Патерни: MVC, CQRS, Event-driven, Microservices. Переваги: 1) Структурованість — модулі, контролери, сервіси. 2) TypeScript-first. 3) DI — тестабельний код. 4) Ecosystem — готові модулі для auth, validation, caching, queues, WebSocket, GraphQL. 5) Підтримка мікросервісів з різними транспортами." },
            { level: "junior", q: "Поясни основні building blocks: Module, Controller, Service, Provider.", a: "Module (@Module) — організаційна одиниця. Об'єднує controllers, providers, imports/exports. Кожен додаток має root AppModule. Controller (@Controller) — обробляє HTTP запити. Декоратори: @Get, @Post, @Put, @Delete, @Param, @Body, @Query. Повертає response. Service (@Injectable) — бізнес-логіка. Ін'єктується в controllers та інші services через DI. Provider — будь-який клас з @Injectable, що може бути ін'єктований: services, repositories, factories, helpers. Реєструється в module providers. Flow: HTTP Request → Controller → Service → Response. Controller тонкий (routing), Service товстий (логіка)." },
            { level: "junior", q: "Що таке Dependency Injection у NestJS? Як він реалізований?", a: "DI — патерн, де залежності передаються ззовні, а не створюються всередині класу. NestJS використовує IoC (Inversion of Control) контейнер. Реалізація: 1) @Injectable() — позначає клас як провайдер. 2) Реєстрація в module: providers: [UserService]. 3) Ін'єкція через constructor: constructor(private userService: UserService). NestJS резолвить залежності автоматично за типом (TypeScript metadata). Custom providers: useClass, useValue, useFactory, useExisting. Приклад useFactory: { provide: 'CONFIG', useFactory: () => loadConfig() }. @Inject('TOKEN') — ін'єкція за токеном. Переваги: тестабельність (легко мокувати), loose coupling, модульність." },
            { level: "middle", q: "Що таке Guards, Interceptors, Pipes, Filters? Поясни порядок виконання.", a: "Guards (@CanActivate) — авторизація, вирішують чи пропустити запит (true/false). Приклад: AuthGuard, RolesGuard. Interceptors (@NestInterceptor) — логіка до/після handler (logging, caching, transform response, timeout). Мають доступ до ExecutionContext і Observable (RxJS). Pipes (@PipeTransform) — валідація та трансформація вхідних даних. Built-in: ValidationPipe, ParseIntPipe, ParseUUIDPipe. Filters (@ExceptionFilter) — обробка exceptions, форматування error responses. Порядок виконання: Middleware → Guards → Interceptors (before) → Pipes → Handler → Interceptors (after) → Filters (при exception). Scope: global (app.useGlobal*), module (@UseGuards на controller/method)." },
            { level: "middle", q: "Що таке DTO та ValidationPipe? Як використовувати class-validator?", a: "DTO (Data Transfer Object) — клас, що описує форму вхідних даних. class CreateUserDto { @IsString() @MinLength(3) name: string; @IsEmail() email: string; }. class-validator — декоратори для валідації: @IsString, @IsNumber, @IsEmail, @MinLength, @MaxLength, @IsOptional, @IsEnum, @ValidateNested. class-transformer — трансформація plain objects в class instances (@Type, @Transform, @Exclude). ValidationPipe: app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true })). whitelist — видаляє невідомі properties. forbidNonWhitelisted — кидає error. transform — автоматичний тип конвертації (string param → number)." },
            { level: "middle", q: "Поясни Custom Decorators. Напиши декоратор для отримання поточного user.", a: "Custom decorators — createParamDecorator для витягування даних з request. Приклад @CurrentUser: export const CurrentUser = createParamDecorator((data: string, ctx: ExecutionContext) => { const request = ctx.switchToHttp().getRequest(); const user = request.user; return data ? user?.[data] : user; }). Використання: @Get('profile') getProfile(@CurrentUser() user: User) або @CurrentUser('email') email: string. Composition: applyDecorators — комбінування кількох декораторів: export function Auth(...roles: Role[]) { return applyDecorators(UseGuards(AuthGuard, RolesGuard), SetMetadata('roles', roles), ApiBearerAuth()); }. SetMetadata + Reflector — передача даних від декоратора до guard/interceptor." },
            { level: "middle", q: "Що таке scope провайдерів: DEFAULT, REQUEST, TRANSIENT?", a: "DEFAULT (Singleton) — один instance на весь додаток (замовчування). Створюється при старті, діється всіма модулями. Найефективніший. REQUEST — новий instance для кожного HTTP запиту. @Injectable({ scope: Scope.REQUEST }). Використання: request-specific дані (current user, locale). Обмеження: всі провайдери що залежать від REQUEST-scoped теж стають REQUEST-scoped (bubble up). Впливає на performance. TRANSIENT — новий instance для кожного inject. Кожен споживач отримує свій instance. Використання: рідко, для stateful providers де кожен модуль потребує ізольований instance. Рекомендація: використовувати DEFAULT максимально, REQUEST тільки коли дійсно потрібен request context, TRANSIENT — рідко." },
            { level: "middle", q: "Як реалізувати аутентифікацію з JWT та Passport у NestJS?", a: "@nestjs/passport + @nestjs/jwt + passport-jwt. 1) AuthModule: JwtModule.register({ secret, signOptions: { expiresIn: '1h' } }). 2) AuthService: login(user) { return { access_token: jwtService.sign({ sub: user.id, email: user.email }) }; }. 3) JwtStrategy extends PassportStrategy(Strategy): validate(payload) { return { id: payload.sub, email: payload.email }; }. 4) JwtAuthGuard extends AuthGuard('jwt'). 5) Використання: @UseGuards(JwtAuthGuard) на контролерах. Refresh tokens: окремий token з довшим expiry, зберігається в httpOnly cookie, окремий endpoint для refresh. Хешування паролів: bcrypt. @Public() декоратор — пропуск auth для окремих endpoints." },
            { level: "middle", q: "Що таке NestJS Modules? Поясни dynamic modules.", a: "Module — логічна група функціональності. @Module({ imports, controllers, providers, exports }). imports — інші модулі (їх exports стають доступні). exports — providers доступні іншим модулям. Global modules: @Global() — доступні всюди без imports. Dynamic modules — модулі з конфігурацією, визначеною при імпорті. Приклад: DatabaseModule.forRoot({ host, port }) — створює module з налаштованими провайдерами. static forRoot(options): DynamicModule { return { module: DatabaseModule, providers: [{ provide: 'DB_OPTIONS', useValue: options }, DatabaseService], exports: [DatabaseService] }; }. forRoot — один раз у AppModule (singleton), forFeature — в feature modules (per-module конфігурація). ConfigModule.forRoot(), TypeOrmModule.forRoot() — типові приклади." },
            { level: "senior", q: "Як реалізувати CQRS pattern у NestJS? Коли він доцільний?", a: "CQRS (Command Query Responsibility Segregation) — розділення операцій читання (Query) і запису (Command). @nestjs/cqrs: Commands — змінюють стан: class CreateUserCommand { constructor(public name: string) {} }. CommandHandler: @CommandHandler(CreateUserCommand) → execute(command). Queries — читають: class GetUserQuery { constructor(public id: string) {} }. QueryHandler: @QueryHandler(GetUserQuery) → execute(query). Events — сповіщення про зміни: class UserCreatedEvent. EventHandler: @EventsHandler(UserCreatedEvent). CommandBus.execute(), QueryBus.execute(). Доцільний: складна бізнес-логіка, різні моделі для read/write, event sourcing, high-read systems (окрема read DB). Недоцільний: прості CRUD, маленькі проєкти — overhead не виправданий." },
            { level: "senior", q: "Поясни Event-driven архітектуру у NestJS: EventEmitter, Microservices.", a: "@nestjs/event-emitter — internal events в межах одного процесу. EventEmitter2 під капотом. Emit: eventEmitter.emit('user.created', payload). Listen: @OnEvent('user.created') handleUserCreated(payload) {}. Wildcard: @OnEvent('user.*'). Async listeners. Використання: decoupling модулів, side effects (send email after registration). Microservices — events між процесами/сервісами. @nestjs/microservices: @EventPattern('user_created') — асинхронна обробка (fire-and-forget). @MessagePattern('get_user') — синхронний request-response. ClientProxy для відправки. Transport-agnostic: один handler працює з будь-яким транспортом. Hybrid application: app.connectMicroservice() — HTTP + microservice в одному процесі." },
            { level: "senior", q: "Як побудувати Microservices у NestJS? Поясни транспорти: TCP, Redis, NATS, Kafka.", a: "NestJS microservices — transport-agnostic. Server: app.connectMicroservice({ transport: Transport.REDIS, options: { host, port } }). Client: ClientsModule.register([{ name: 'USER_SERVICE', transport: Transport.REDIS }]). TCP — прямий зв'язок, найпростіший, для internal services. Redis — pub/sub, простий setup, message broker. Не гарантує delivery. NATS — lightweight messaging, request-reply + pub/sub, cloud-native. Швидкий, at-most-once. Kafka — distributed event streaming, persistent logs, consumer groups, at-least-once delivery. Для high-throughput, event sourcing. Вибір: TCP — простий dev, Redis — medium scale, NATS — cloud-native microservices, Kafka — enterprise event streaming. gRPC також підтримується — для high-performance бінарного протоколу." },
            { level: "senior", q: "Що таке NestJS execution context? Як зробити guard, який працює і для HTTP і для WebSocket?", a: "ExecutionContext extends ArgumentsHost — надає інформацію про поточний execution pipeline. Методи: getType() → 'http' | 'ws' | 'rpc'. switchToHttp() → getRequest(), getResponse(). switchToWs() → getClient(), getData(). switchToRpc() → getContext(), getData(). getHandler(), getClass() — reflector metadata. Universal guard: @Injectable() export class AuthGuard implements CanActivate { canActivate(context: ExecutionContext) { const type = context.getType(); if (type === 'http') { const req = context.switchToHttp().getRequest(); return validateToken(req.headers.authorization); } if (type === 'ws') { const client = context.switchToWs().getClient(); return validateToken(client.handshake.auth.token); } } }. Reflector: this.reflector.get('roles', context.getHandler()) — читання metadata з декораторів." },
            { level: "senior", q: "Як тестувати NestJS: unit tests з TestingModule, e2e тести?", a: "Unit tests: TestingModule створює ізольований модуль з моками. const module = await Test.createTestingModule({ providers: [UserService, { provide: UserRepository, useValue: mockRepo }] }).compile(); const service = module.get(UserService). Мокування: jest.fn(), jest.spyOn. Тестувати бізнес-логіку в services. E2E tests: const app = await Test.createTestingModule({ imports: [AppModule] }).compile().then(m => m.createNestApplication()); await app.init(); Supertest: request(app.getHttpServer()).get('/users').expect(200). Test database: in-memory MongoDB (mongodb-memory-server) або test containers. Стратегія: unit tests для services, e2e для API endpoints, integration для modules з реальними залежностями." },
            { level: "senior", q: "Як оптимізувати NestJS додаток для high-load? Connection pooling, caching, queue.", a: "Connection pooling: TypeORM/Mongoose — налаштувати pool size (poolSize: 10). Не створювати з'єднання per-request. PgBouncer для PostgreSQL. Caching: @nestjs/cache-manager — in-memory або Redis. @CacheInterceptor на controller. CacheKey, CacheTTL декоратори. Manual: cacheManager.get/set. Cache invalidation стратегія. Queue: @nestjs/bull (Redis-based). Відкладені задачі, email sending, image processing. @Process() handler, concurrency control. Додатково: 1) Fastify замість Express (2-3x швидший). 2) Compression middleware. 3) Rate limiting (@nestjs/throttler). 4) Clustering (PM2). 5) Database indexes, query optimization. 6) Lazy loading modules. 7) Response serialization (ClassSerializerInterceptor). 8) Horizontal scaling + load balancer." },
        ],
    },
    "MongoDB": {
        icon: "🍃",
        color: "#4db33d",
        questions: [
            { level: "junior", q: "Що таке MongoDB? Яка основна різниця з реляційними БД?", a: "MongoDB — NoSQL документо-орієнтована база даних. Зберігає дані як BSON документи (binary JSON). Різниця з RDBMS: 1) Schema-less — документи в одній колекції можуть мати різну структуру (flexible schema). 2) Документи замість рядків — вкладені об'єкти і масиви (denormalization). 3) Немає JOIN-ів (є $lookup, але менш ефективний). 4) Горизонтальне масштабування (sharding) простіше. 5) Eventual consistency за замовчуванням (configurable). Коли MongoDB: часто змінювана schema, ієрархічні дані, високий write throughput, прототипування. Коли RDBMS: складні зв'язки, транзакції, strict consistency, складні запити з JOIN." },
            { level: "junior", q: "Що таке документ та колекція у MongoDB?", a: "Документ — базова одиниця даних (аналог row у SQL). BSON формат (Binary JSON). Підтримує: strings, numbers, booleans, arrays, nested objects, dates, ObjectId, binary data. Максимальний розмір: 16MB. Кожен документ має унікальний _id. Колекція — група документів (аналог table). Не вимагає однакової структури документів (schema-less). Створюється автоматично при першому insert. Namespace: database.collection. Capped collections — фіксований розмір, FIFO порядок (для логів). Views — read-only колекції на основі aggregation pipeline. Validator — можна задати JSON Schema для валідації документів при insert/update." },
            { level: "junior", q: "Поясни базові CRUD операції у MongoDB.", a: "Create: insertOne({ name: 'John', age: 30 }), insertMany([doc1, doc2]). Повертає insertedId(s). Read: find({ age: { $gt: 25 } }) — повертає cursor. findOne() — один документ. Проекція: find({}, { name: 1, _id: 0 }). Оператори: $eq, $gt, $lt, $in, $and, $or, $regex. Update: updateOne({ _id: id }, { $set: { name: 'Jane' } }). updateMany(). Оператори: $set, $unset, $inc, $push, $pull, $addToSet. replaceOne — заміна всього документа. Delete: deleteOne({ _id: id }), deleteMany({ status: 'inactive' }). findOneAndUpdate/Delete — повертає документ. Bulk operations: bulkWrite([{ insertOne: {} }, { updateOne: {} }]) — атомарна batch операція." },
            { level: "junior", q: "Що таке ObjectId? Яка його структура?", a: "ObjectId — 12-байтний унікальний ідентифікатор, за замовчуванням для _id. Структура (MongoDB 3.4+): 4 байти — timestamp (Unix epoch seconds), 5 байтів — random value (unique per machine/process), 3 байти — incrementing counter (initialized randomly). Переваги: 1) Глобально унікальний без координації. 2) Містить timestamp — можна витягнути час створення: ObjectId.getTimestamp(). 3) Монотонно зростає — хороший для індексації (sequential writes). 4) Не потребує auto-increment (який складний у distributed системах). Недоліки: не human-readable, 24 hex chars. Можна використовувати custom _id (string, number), але ObjectId — рекомендований." },
            { level: "middle", q: "Поясни embedded documents vs references. Коли що використовувати?", a: "Embedding (денормалізація) — вкладений документ: { user: 'John', address: { city: 'Kyiv', street: '...' } }. References (нормалізація) — посилання на інший документ: { user: 'John', addressId: ObjectId('...') }. Embedding коли: 1) One-to-one або one-to-few зв'язок. 2) Дані завжди читаються разом. 3) Дані не змінюються часто. 4) Документ не перевищить 16MB. References коли: 1) Many-to-many зв'язок. 2) Дані змінюються незалежно. 3) Великі вкладені масиви (unbounded growth). 4) Дані потрібні окремо. Гібрид: часткове embedding (summary + reference). Правило: \"Data that is accessed together should be stored together.\" Anti-pattern: unbounded arrays (embedded comments list that grows infinitely)." },
            { level: "middle", q: "Що таке aggregation pipeline? Поясни `$match`, `$group`, `$lookup`, `$project`.", a: "Aggregation pipeline — послідовність етапів обробки документів. Кожен етап трансформує вхід. $match — фільтрація документів (як find): { $match: { status: 'active' } }. Ставити рано для performance. $group — групування та агрегація: { $group: { _id: '$category', total: { $sum: '$price' }, count: { $sum: 1 }, avg: { $avg: '$price' } } }. $lookup — LEFT JOIN з іншою колекцією: { $lookup: { from: 'authors', localField: 'authorId', foreignField: '_id', as: 'author' } }. $project — вибірка/трансформація полів: { $project: { name: 1, total: { $multiply: ['$price', '$qty'] } } }. Інші: $sort, $limit, $skip, $unwind (розгортання масиву), $facet (паралельні pipeline), $addFields, $merge." },
            { level: "middle", q: "Як працюють індекси у MongoDB? Поясни типи: single, compound, multikey, text.", a: "Індекси — B-tree структури для швидкого пошуку (замість collection scan). Без індексу — O(n). Single field: db.users.createIndex({ email: 1 }). 1 = ascending, -1 = descending. Compound: createIndex({ lastName: 1, firstName: 1 }) — порядок важливий (ESR rule: Equality, Sort, Range). Multikey: автоматично для масивів. { tags: ['js', 'react'] } → індекс по кожному елементу. Text: createIndex({ content: 'text' }) — повнотекстовий пошук. $text operator. Інші: Unique (unique: true), Sparse (тільки документи з полем), Partial (filter expression), TTL (auto-delete), Geospatial (2d, 2dsphere). Compound index підтримує запити по prefix: {a, b, c} → підтримує {a}, {a, b}, {a, b, c}." },
            { level: "middle", q: "Що таке Mongoose? Поясни Schema, Model, Document.", a: "Mongoose — ODM (Object Document Mapping) для MongoDB і Node.js. Додає структуру та валідацію поверх schema-less MongoDB. Schema — визначає структуру документа: const userSchema = new Schema({ name: { type: String, required: true, trim: true }, age: { type: Number, min: 0 }, email: { type: String, unique: true } }). Middleware: pre/post hooks (save, validate, remove). Virtuals: обчислювані поля. Methods/statics. Model — компільована schema, клас для роботи з колекцією: const User = mongoose.model('User', userSchema). CRUD: User.find(), User.create(), User.findByIdAndUpdate(). Document — instance моделі: const user = new User({ name: 'John' }); await user.save(). Має методи: toJSON, toObject, populate." },
            { level: "middle", q: "Поясни транзакції у MongoDB. Коли їх потрібно використовувати?", a: "Транзакції (MongoDB 4.0+) — ACID гарантії для операцій над кількома документами/колекціями. Multi-document transactions: const session = await mongoose.startSession(); session.startTransaction(); try { await Order.create([order], { session }); await Inventory.updateOne({ _id: itemId }, { $inc: { qty: -1 } }, { session }); await session.commitTransaction(); } catch (e) { await session.abortTransaction(); } finally { session.endSession(); }. Коли потрібні: 1) Переказ коштів (debit + credit). 2) Створення пов'язаних документів (order + payment). 3) Операції, де часткове виконання неприпустиме. Коли НЕ потрібні: single document updates (вже атомарні), embedded documents. Обмеження: потребують replica set, overhead performance, max 60с." },
            { level: "middle", q: "Що таке TTL index? Де він корисний?", a: "TTL (Time-To-Live) index — автоматичне видалення документів після закінчення терміну. Створення: db.sessions.createIndex({ createdAt: 1 }, { expireAfterSeconds: 3600 }) — документи видаляються через 1 годину після createdAt. MongoDB background thread перевіряє кожні 60 секунд. Де корисний: 1) Сесії — автоматичний cleanup. 2) Тимчасові токени (email verification, password reset). 3) Кеш — auto-expiration. 4) Логи — зберігати тільки останні N днів. 5) OTP коди. Обмеження: поле має бути Date тип, працює тільки на single field index, видалення не моментальне (background процес, до 60с затримки). Не можна на capped collections. expireAfterSeconds: 0 — видаляється точно у вказаний час у полі." },
            { level: "senior", q: "Поясни replica set у MongoDB. Що таке PRIMARY/SECONDARY/ARBITER?", a: "Replica set — група mongod processes з однаковими даними для high availability. PRIMARY — приймає всі write операції, один у replica set. Записує операції в oplog (operations log). SECONDARY — реплікує дані з PRIMARY через oplog. Read operations (з readPreference). Може стати PRIMARY при failover. ARBITER — не зберігає дані, тільки голосує при виборах PRIMARY (для непарної кількості). Election: при недоступності PRIMARY — автоматичні вибори (heartbeat кожні 2с, election timeout 10с). Majority — потрібна більшість голосів. Мінімум: 3 members (або 2 data + 1 arbiter). Read preferences: primary, primaryPreferred, secondary, secondaryPreferred, nearest. Oplog — capped collection з write operations." },
            { level: "senior", q: "Що таке sharding? Як обрати shard key? Які є проблеми?", a: "Sharding — горизонтальне розподілення даних між кількома серверами (shards). Кожен shard містить subset даних. Components: shard (replica set з даними), config servers (metadata, chunk mapping), mongos (router, приймає запити від клієнтів). Shard key — поле, за яким розподіляються дані. Вибір критичний і незмінний. Хороший shard key: 1) High cardinality (багато унікальних значень). 2) Low frequency (рівномірний розподіл). 3) Non-monotonic (не auto-increment, інакше все на одному shard). Стратегії: hashed (рівномірний розподіл, але range queries повільні), ranged (хороший для range queries, ризик hot spots). Проблеми: scatter-gather queries (запит до всіх shards), jumbo chunks, нерівномірний розподіл, складність operations." },
            { level: "senior", q: "Як аналізувати slow queries у MongoDB? Поясни explain() та query planner.", a: "Profiler: db.setProfilingLevel(1, { slowms: 100 }) — логує запити повільніші за 100ms у system.profile collection. explain() — аналіз execution plan: db.users.find({ age: { $gt: 25 } }).explain('executionStats'). Важливі поля: 1) queryPlanner.winningPlan — обраний план (IXSCAN vs COLLSCAN). 2) executionStats.totalDocsExamined — скільки документів переглянуто. 3) executionStats.nReturned — скільки повернуто. 4) Ratio examined/returned — має бути близько до 1. 5) executionTimeMillis. COLLSCAN — full collection scan (потрібен індекс). IXSCAN — index scan (добре). SORT — in-memory сортування (потрібен compound index). MongoDB Compass — візуальний explain. Рекомендації: compound indexes за ESR rule, covered queries (projection тільки indexed fields)." },
            { level: "senior", q: "Що таке write concern та read concern? Як вони впливають на консистентність?", a: "Write concern — скільки replica members повинні підтвердити write. w: 0 — fire-and-forget (найшвидше, ризик втрати). w: 1 — primary confirmed (default). w: 'majority' — більшість підтвердила (durable, але повільніше). j: true — запис у journal на диску. Read concern — рівень ізоляції читання. 'local' — повертає найновіші дані з поточного member (default). 'available' — як local, але для sharded. 'majority' — тільки committed більшістю дані. 'linearizable' — найсуворіший, гарантує real-time read. 'snapshot' — для транзакцій. Trade-offs: stronger consistency = higher latency. Для критичних даних (фінанси): writeConcern: { w: 'majority', j: true } + readConcern: 'majority'. Для логів/метрик: w: 1, readConcern: 'local'." },
            { level: "senior", q: "Поясни change streams у MongoDB. Де вони використовуються?", a: "Change streams — real-time потік змін у колекції/базі/кластері. Побудований на oplog. API: const stream = db.collection('orders').watch([{ $match: { operationType: 'insert' } }]); stream.on('change', (change) => { /* operationType, fullDocument, updateDescription */ }). Підтримує pipeline для фільтрації. Resume token — відновлення після disconnect. Операції: insert, update, replace, delete, drop, rename. Де використовуються: 1) Real-time notifications (нове замовлення → push). 2) Event-driven architecture — trigger на зміни в БД. 3) Data sync — реплікація в іншу систему (Elasticsearch, cache invalidation). 4) Audit log. 5) ETL pipelines. Вимоги: replica set або sharded cluster. Альтернатива polling. Обмеження: не для дуже high-throughput (oplog розмір)." },
            { level: "senior", q: "Як уникнути N+1 проблеми при роботі з Mongoose та пов'язаними документами?", a: "N+1 у Mongoose: завантажити N документів, потім для кожного окремий populate запит. Рішення: 1) populate() — Mongoose автоматично робить $in запит: User.find().populate('posts') → 2 запити замість N+1. Nested: populate({ path: 'posts', populate: { path: 'comments' } }). 2) Aggregation $lookup — один запит з JOIN на рівні БД (ефективніше за populate). 3) Embedding — якщо дані часто читаються разом, вбудувати. 4) Lean queries — .lean() повертає plain objects (швидше, менше пам'яті). 5) Select тільки потрібні поля: .populate('author', 'name email'). 6) Virtual populate для зворотних зв'язків (hasMany). 7) DataLoader pattern — batch + deduplicate для GraphQL resolvers." },
        ],
    },
    "Security": {
        icon: "🔒",
        color: "#e74c3c",
        questions: [
            { level: "junior", q: "Що таке XSS? Як захиститися?", a: "XSS (Cross-Site Scripting) — ін'єкція шкідливого JS коду в сторінку. Типи: 1) Stored — скрипт зберігається в БД (коментарі), виконується у всіх відвідувачів. Найнебезпечніший. 2) Reflected — скрипт у URL параметрі, виконується при переході за посиланням. 3) DOM-based — маніпуляція DOM через JS (innerHTML, eval). Захист: 1) Escaping output — HTML entities (<script> → &lt;script&gt;). React робить це автоматично. 2) НЕ використовувати dangerouslySetInnerHTML (або sanitize: DOMPurify). 3) Content Security Policy (CSP) header. 4) httpOnly cookies — JS не має доступу. 5) Input validation на сервері. 6) X-XSS-Protection header (legacy)." },
            { level: "junior", q: "Що таке CSRF? Як захиститися?", a: "CSRF (Cross-Site Request Forgery) — атака, де шкідливий сайт виконує запит від імені авторизованого користувача. Приклад: користувач залогінений в банку, відвідує шкідливий сайт з формою, що робить POST на bank.com/transfer. Browser автоматично додає cookies. Захист: 1) CSRF token — унікальний токен у формі, перевіряється сервером. 2) SameSite cookies: SameSite=Strict або Lax — cookie не відправляється з cross-site запитів. 3) Перевірка Origin/Referer headers. 4) Custom headers (X-Requested-With) — CORS не дозволяє custom headers з іншого origin. 5) Double submit cookie pattern. SPA з JWT в localStorage не вразливі до CSRF (але вразливі до XSS)." },
            { level: "middle", q: "Що таке CORS? Як налаштувати правильно?", a: "CORS (Cross-Origin Resource Sharing) — механізм, що дозволяє серверу вказати, які origins можуть звертатися до його ресурсів. Preflight request: перед \"складним\" запитом (з custom headers, PUT/DELETE) браузер надсилає OPTIONS. Відповідь: Access-Control-Allow-Origin, Allow-Methods, Allow-Headers, Max-Age. Налаштування: 1) Не використовувати Access-Control-Allow-Origin: * з credentials. 2) Вказати конкретні origins: ['https://myapp.com']. 3) Обмежити methods та headers. 4) credentials: true тільки якщо потрібні cookies. Express: app.use(cors({ origin: ['https://myapp.com'], methods: ['GET', 'POST'], credentials: true })). NestJS: app.enableCors({ origin, credentials }). Типова помилка: CORS не захищає API — це browser policy." },
            { level: "middle", q: "Поясни JWT. Яка структура? Де зберігати: localStorage vs httpOnly cookie?", a: "JWT (JSON Web Token) — self-contained token для авторизації. Структура: Header.Payload.Signature (base64url). Header: { alg: 'HS256', typ: 'JWT' }. Payload: { sub: userId, exp: timestamp, iat: timestamp, roles: [...] }. Signature: HMAC(header + '.' + payload, secret). Зберігання: localStorage — доступний з JS (XSS вразливість!), простіший для SPA. httpOnly cookie — НЕ доступний з JS (захист від XSS), автоматично додається до запитів, потрібен CSRF захист. Рекомендація: httpOnly cookie + SameSite=Strict. Refresh token в httpOnly cookie, access token короткоживучий (15 хв). Не зберігати sensitive дані в payload (він тільки base64, не зашифрований)." },
            { level: "middle", q: "Що таке SQL Injection та NoSQL Injection? Як захиститися?", a: "SQL Injection — ін'єкція SQL коду через user input: SELECT * FROM users WHERE name = 'admin'; DROP TABLE users; --'. NoSQL Injection — ін'єкція MongoDB операторів: { username: { $gt: '' }, password: { $gt: '' } } — обходить авторизацію. Або: { $where: 'this.password.length > 0' }. Захист SQL: 1) Parameterized queries / prepared statements (НІКОЛИ не конкатенувати user input). 2) ORM (TypeORM, Prisma). 3) Input validation. Захист NoSQL: 1) Валідація типів — перевіряти що input === string (не object). 2) Mongoose schema validation. 3) express-mongo-sanitize — видаляє $ і . з req.body. 4) Не використовувати $where. 5) Principle of least privilege для DB user." },
            { level: "middle", q: "Що таке Content Security Policy (CSP)?", a: "CSP — HTTP header, що визначає дозволені джерела контенту для сторінки. Захищає від XSS, clickjacking, code injection. Директиви: default-src 'self' — тільки свій origin. script-src 'self' 'nonce-abc123' — скрипти тільки свої та з nonce. style-src 'self' 'unsafe-inline' — стилі (unsafe-inline для inline styles). img-src * — зображення з будь-якого джерела. connect-src 'self' api.example.com — API запити. frame-ancestors 'none' — захист від clickjacking. report-uri /csp-report — звіт про порушення. Рекомендації: починати з Content-Security-Policy-Report-Only (тільки логи, не блокує). Поступово додавати обмеження. Next.js: налаштувати в next.config.js headers." },
            { level: "senior", q: "Порівняй OAuth 2.0 та OpenID Connect. Поясни flows: Authorization Code, PKCE.", a: "OAuth 2.0 — протокол АВТОРИЗАЦІЇ (delegation). Надає access token для доступу до ресурсів. Не надає інформацію про користувача. OpenID Connect (OIDC) — надбудова над OAuth 2.0 для АВТЕНТИФІКАЦІЇ. Додає id_token (JWT з інформацією про user), userinfo endpoint, стандартні scopes (openid, profile, email). Authorization Code flow (для server apps): 1) Redirect на auth server. 2) User логіниться, погоджується. 3) Auth server redirect з code. 4) Server обмінює code на tokens (server-to-server). Безпечний — tokens не потрапляють у browser. PKCE (Proof Key for Code Exchange) — для SPA/mobile (без client_secret). Client генерує code_verifier + code_challenge. Auth server перевіряє challenge при обміні code → tokens. Запобігає interception attack." },
            { level: "senior", q: "Що таке rate limiting? Як реалізувати з distributed cache?", a: "Rate limiting — обмеження кількості запитів від клієнта за період часу. Захист від: DDoS, brute force, API abuse. Алгоритми: 1) Fixed Window — N запитів за період (проблема: burst на межі вікон). 2) Sliding Window — плавніший, комбінує поточне і попереднє вікно. 3) Token Bucket — N токенів, поповнюються з часом, запит забирає токен. 4) Leaky Bucket — фіксована швидкість обробки. Distributed (Redis): INCR key + EXPIRE: const count = await redis.incr(`rate:${ip}`); if (count === 1) await redis.expire(`rate:${ip}`, 60); if (count > 100) return 429. Або redis-cell module (Token Bucket на Redis). Headers: X-RateLimit-Limit, X-RateLimit-Remaining, Retry-After. NestJS: @nestjs/throttler. Express: express-rate-limit + rate-limit-redis." },
            { level: "senior", q: "Поясни OWASP Top 10. Які найкритичніші для SPA/API?", a: "OWASP Top 10 (2021): 1) Broken Access Control — відсутня перевірка авторизації (IDOR, прямий доступ до ресурсів). 2) Cryptographic Failures — слабке шифрування, відкриті секрети. 3) Injection — SQL/NoSQL/XSS injection. 4) Insecure Design — архітектурні проблеми. 5) Security Misconfiguration — default credentials, verbose errors, open ports. 6) Vulnerable Components — залежності з відомими CVE. 7) Auth Failures — слабкі паролі, відсутній brute-force захист. 8) Data Integrity — insecure deserialization, untrusted CI/CD. 9) Logging Failures — відсутній audit trail. 10) SSRF — server робить запити за вказівкою клієнта. Для SPA/API найкритичніші: Broken Access Control (IDOR), Injection (XSS), Auth Failures (JWT misconfiguration), SSRF." },
            { level: "senior", q: "Як безпечно зберігати паролі? Поясни bcrypt, scrypt, Argon2.", a: "НІКОЛИ: plain text, MD5, SHA-256 (швидкі — brute force). Потрібні slow hashing functions з salt. bcrypt — найпоширеніший. Salt вбудований в hash. Cost factor (rounds) — регулює повільність (10-12 recommended). $2b$10$salt22chars.hash31chars. scrypt — memory-hard (вимагає багато RAM для паралельного bruteforce). Параметри: N (CPU/memory cost), r (block size), p (parallelization). Argon2 — winner PHC (2015), найсучасніший. Варіанти: Argon2id (recommended — комбінує захист від GPU і side-channel attacks). Параметри: memory, iterations, parallelism. Рекомендація: Argon2id > bcrypt > scrypt. В Node.js: bcrypt (npm) або argon2 (npm). Додатково: pepper (server-side secret) на додаток до salt." },
        ],
    },
    "Architecture & Patterns": {
        icon: "🏗️",
        color: "#9b59b6",
        questions: [
            { level: "middle", q: "Що таке SOLID принципи? Наведи приклади для JS/TS.", a: "S — Single Responsibility: клас/модуль має одну причину для зміни. UserService не повинен відправляти email. O — Open/Closed: відкритий для розширення, закритий для модифікації. Strategy pattern замість if/else. L — Liskov Substitution: підклас можна підставити замість батьківського без поломки. Не throw у методах, які батько не throws. I — Interface Segregation: краще кілька маленьких інтерфейсів, ніж один великий. interface Readable, Writable замість interface ReadWritable. D — Dependency Inversion: залежати від абстракцій (interface), не від конкретних реалізацій. constructor(private repo: UserRepository) — interface, не конкретний MongoUserRepository. NestJS DI природно реалізує D." },
            { level: "middle", q: "Поясни DRY, KISS, YAGNI принципи.", a: "DRY (Don't Repeat Yourself) — уникати дублювання ЗНАНЬ (не коду!). Якщо бізнес-правило змінюється — змінити потрібно в одному місці. Але: передчасна абстракція гірша за дублювання. Три повтори — тоді абстрагувати (Rule of Three). KISS (Keep It Simple, Stupid) — найпростіше рішення, що працює. Уникати overengineering, premature optimization, зайвих абстракцій. Простий код легше читати, дебажити, підтримувати. YAGNI (You Aren't Gonna Need It) — не реалізовувати функціональність \"на майбутнє\". Код для гіпотетичних вимог = зайва складність, зайві тести, зайва підтримка. Реалізовувати тільки те, що потрібно ЗАРАЗ. Баланс: DRY без фанатизму, KISS завжди, YAGNI — відкладай до потреби." },
            { level: "middle", q: "Що таке Clean Architecture? Які шари вона має?", a: "Clean Architecture (Robert C. Martin) — розділення додатку на шари з правилом залежностей: зовнішні шари залежать від внутрішніх, НІКОЛИ навпаки. Шари (від центру): 1) Entities — бізнес-правила, доменні об'єкти. Не залежать від нічого. 2) Use Cases (Application) — бізнес-логіка додатку, orchestration. Залежить тільки від Entities. 3) Interface Adapters — контролери, презентери, gateway implementations. Конвертація даних між форматами. 4) Frameworks & Drivers — зовнішні інструменти: DB, web framework, UI. Dependency Rule: import тільки всередину (controllers → use cases → entities). Інверсія залежностей через interfaces. У NestJS: Controller → Service (Use Case) → Repository (interface) → MongoRepository (impl)." },
            { level: "middle", q: "Поясни Repository Pattern. Як він застосовується з MongoDB/NestJS?", a: "Repository Pattern — абстракція доступу до даних. Бізнес-логіка працює з interface, не знає про конкретну БД. Interface: interface UserRepository { findById(id: string): Promise<User>; save(user: User): Promise<User>; delete(id: string): Promise<void>; }. Implementation: @Injectable() class MongoUserRepository implements UserRepository { constructor(@InjectModel(User.name) private model: Model<User>) {} async findById(id: string) { return this.model.findById(id).lean(); } }. NestJS DI: providers: [{ provide: 'UserRepository', useClass: MongoUserRepository }]. Service: constructor(@Inject('UserRepository') private repo: UserRepository). Переваги: тестабельність (mock repository), заміна БД без зміни бізнес-логіки, чіткий контракт." },
            { level: "senior", q: "Що таке Domain-Driven Design (DDD)? Поясни основні концепції: aggregate, entity, value object.", a: "DDD — підхід до проєктування складного ПЗ навколо бізнес-домену. Entity — об'єкт з унікальною ідентичністю (User, Order). Ідентичність зберігається при зміні атрибутів. Value Object — об'єкт без ідентичності, визначається значеннями (Money, Address, Email). Immutable. Два Money(100, 'USD') — рівні. Aggregate — кластер пов'язаних Entity та Value Objects з одним Aggregate Root (точка входу). Правила: зовнішній код звертається тільки через Root, Root гарантує консистентність. Приклад: Order (root) → OrderItem (entity) → Money (VO). Bounded Context — межі, де model має конкретне значення. Ubiquitous Language — спільна мова розробників і бізнесу. DDD доцільний для complex domain, не для CRUD." },
            { level: "senior", q: "Що таке Event Sourcing та Event-Driven Architecture?", a: "Event-Driven Architecture — система, де компоненти комунікують через events. Producer → Event Bus → Consumer. Async, loose coupling. Патерни: pub/sub, event notification, event-carried state transfer. Event Sourcing — зберігання стану як послідовності events (не snapshot). Замість UPDATE balance = 100 → зберігаємо: MoneyDeposited(50), MoneyWithdrawn(20), MoneyDeposited(70). Поточний стан = replay всіх events. Переваги: повний audit trail, time-travel, rebuild state, multiple projections (read models). Недоліки: складність, eventual consistency, event versioning, schema evolution, storage growth. CQRS часто поєднується з Event Sourcing: write через events, read з оптимізованих projections. Kafka/EventStore — типові technologies." },
            { level: "senior", q: "Порівняй monolith vs microservices. Коли що обирати?", a: "Monolith — один deployable unit, одна кодова база, одна БД. Переваги: простота розробки/deploy/debug, no network overhead, транзакції прості, один tech stack. Microservices — окремо deployed сервіси, кожен з власною БД. Переваги: незалежний deploy/scaling, technology diversity, fault isolation, team autonomy. Недоліки: distributed system complexity, network latency, data consistency, operational overhead (monitoring, tracing). Коли monolith: стартап, маленька команда, неясний домен, MVP. Коли microservices: великі команди (2-pizza rule), різні scaling потреби, чіткі domain boundaries, потреба в technology diversity. Міграція: Monolith → Modular Monolith → Microservices. Strangler Fig pattern — поступова міграція." },
            { level: "senior", q: "Що таке API Gateway pattern? Яку роль він відіграє у мікросервісах?", a: "API Gateway — єдиний entry point для всіх клієнтських запитів у мікросервісній архітектурі. Роль: 1) Routing — направлення запитів до відповідних сервісів. 2) Authentication/Authorization — централізована перевірка. 3) Rate limiting — захист від abuse. 4) Load balancing. 5) Request aggregation — один клієнтський запит → кілька внутрішніх запитів (BFF pattern). 6) Protocol translation — REST ↔ gRPC. 7) Caching. 8) Logging/monitoring — centralized observability. 9) SSL termination. Інструменти: Kong, AWS API Gateway, Nginx, Traefik, KrakenD. BFF (Backend for Frontend) — окремий gateway для кожного клієнта (web, mobile). Недоліки: single point of failure, додатковий hop, потребує high availability." },
            { level: "senior", q: "Поясни CAP теорему. Як вона впливає на вибір бази даних?", a: "CAP теорема: distributed система може гарантувати тільки 2 з 3: Consistency — всі nodes бачать однакові дані. Availability — кожен запит отримує відповідь. Partition tolerance — система працює при network partition (обов'язковий у distributed). При partition вибір: CP або AP. CP (Consistency + Partition tolerance): при partition — недоступність поки не синхронізуються. MongoDB (w: majority), PostgreSQL, Redis Cluster. Для: фінанси, inventory. AP (Availability + Partition tolerance): при partition — відповідає можливо stale даними. Cassandra, CouchDB, DynamoDB. Для: social media, analytics. На практиці: PACELC — розширення: якщо Partition → вибір A чи C, Else → вибір Latency чи Consistency. Більшість систем — eventually consistent з tunable consistency." },
            { level: "senior", q: "Що таке Circuit Breaker pattern? Як реалізувати?", a: "Circuit Breaker — запобігає cascading failures при взаємодії з unreliable сервісами. Стани: 1) CLOSED — запити проходять нормально, рахуються помилки. 2) OPEN — після N помилок — всі запити одразу fail (fast-fail, не чекаємо timeout). Повертає fallback. 3) HALF-OPEN — після timeout пропускає один запит: успіх → CLOSED, помилка → OPEN. Реалізація: class CircuitBreaker { failures = 0; state = 'CLOSED'; lastFailure = 0; async call(fn) { if (this.state === 'OPEN') { if (Date.now() - this.lastFailure > timeout) this.state = 'HALF_OPEN'; else throw new Error('Circuit open'); } try { const result = await fn(); this.reset(); return result; } catch(e) { this.failures++; if (this.failures >= threshold) { this.state = 'OPEN'; this.lastFailure = Date.now(); } throw e; } } }. Бібліотеки: opossum (Node.js), cockatiel." },
            { level: "senior", q: "Як ти проєктуєш REST API? Поясни принципи: versioning, pagination, filtering, error format.", a: "Versioning: URL (/api/v1/users) — найпростіший, явний. Header (Accept: application/vnd.api.v1+json) — чистіший, складніший. Query param (?version=1). Pagination: cursor-based (after=lastId, limit=20) — стабільний при insert/delete. Offset-based (?page=2&limit=20) — простіший, проблеми з drift. Link headers або response meta. Filtering: query params: ?status=active&sort=-createdAt&fields=name,email. Складні фільтри: ?filter[age][gte]=18. Error format: { status: 404, code: 'USER_NOT_FOUND', message: 'User not found', details: [...] }. HTTP status codes правильно: 200 OK, 201 Created, 204 No Content, 400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found, 409 Conflict, 422 Validation Error, 500 Internal." },
            { level: "senior", q: "Що таке GraphQL? Коли він кращий за REST? Які проблеми (N+1, over-fetching)?", a: "GraphQL — query language для API. Клієнт запитує точно ті дані, які потрібні. Schema: type User { id: ID!, name: String!, posts: [Post!]! }. Query: { user(id: 1) { name, posts { title } } }. Mutations для write, Subscriptions для real-time. Кращий за REST коли: 1) Різні клієнти потребують різні дані (mobile vs web). 2) Складні nested дані. 3) Over-fetching проблема (REST повертає зайві поля). 4) Under-fetching (потрібно кілька REST endpoints). Проблеми: N+1 — resolver для posts викликається для кожного user. Рішення: DataLoader (batch + cache). Security: complexity limiting (max depth, cost analysis), rate limiting по query cost. Caching складніший ніж REST (один endpoint). Performance: persisted queries, automatic persisted queries. Інструменти: Apollo, urql, graphql-yoga." },
        ],
    },
    "DevOps / Infrastructure": {
        icon: "🐳",
        color: "#2496ed",
        questions: [
            { level: "middle", q: "Що таке Docker? Поясни image vs container, Dockerfile.", a: "Docker — платформа контейнеризації. Image — read-only шаблон (snapshot файлової системи + metadata). Container — запущений instance image (ізольований процес з власною FS, мережею, PID). Dockerfile: FROM node:20-alpine (базовий image), WORKDIR /app, COPY package*.json ./, RUN npm ci, COPY . ., EXPOSE 3000, CMD ['node', 'dist/main.js']. Multi-stage builds: FROM node AS builder → RUN npm run build → FROM node:alpine → COPY --from=builder /app/dist — менший фінальний image. Шари (layers): кожна інструкція = layer, кешуються. .dockerignore — виключити node_modules, .git. Best practices: non-root user, specific tags (не latest), мінімальні images (alpine), COPY package.json перед кодом (cache npm install)." },
            { level: "middle", q: "Що таке docker-compose? Як ним користуватися для dev оточення?", a: "docker-compose — інструмент для запуску multi-container додатків. docker-compose.yml визначає services, networks, volumes. Приклад dev: version: '3.8', services: { app: { build: ., ports: ['3000:3000'], volumes: ['./src:/app/src'] (hot reload), depends_on: [db, redis], environment: [DATABASE_URL] }, db: { image: 'mongo:7', ports: ['27017:27017'], volumes: ['mongo_data:/data/db'] }, redis: { image: 'redis:7-alpine' } }. Команди: docker-compose up -d (запуск), docker-compose down (зупинка), docker-compose logs app. Volumes для persistence (БД дані зберігаються між restarts). Networks — сервіси бачать один одного по імені (db:27017). Override: docker-compose.override.yml для dev-specific config." },
            { level: "middle", q: "Поясни основні концепції CI/CD. Які інструменти ти використовував?", a: "CI (Continuous Integration) — автоматичний build + тести при кожному commit/PR. Виявляє проблеми рано. Етапи: lint → type check → unit tests → integration tests → build. CD (Continuous Delivery) — автоматична підготовка до deploy (потрібен manual approval). Continuous Deployment — автоматичний deploy після проходження всіх перевірок. Pipeline: commit → CI (tests, build) → CD (deploy to staging) → manual approval → production. Інструменти: GitHub Actions — найпопулярніший, YAML конфіг, marketplace actions. GitLab CI — вбудований у GitLab. Jenkins — self-hosted, найгнучкіший. CircleCI, Travis CI. Docker — консистентне середовище. Практики: fast feedback (< 10хв), паралельні jobs, caching (node_modules), branch protection rules." },
            { level: "middle", q: "Що таке environment variables? Як безпечно їх зберігати?", a: "Environment variables — конфігурація, що залежить від середовища (dev/staging/prod). Приклади: DATABASE_URL, JWT_SECRET, API_KEYS. 12-Factor App принцип: конфігурація в env vars, не в коді. Зберігання: 1) .env файли (dotenv) — тільки для local dev, НЕ коммітити в git (.gitignore). .env.example — шаблон без значень. 2) CI/CD secrets — GitHub Secrets, GitLab CI Variables. Зашифровані, доступні тільки в pipeline. 3) Cloud secret managers — AWS Secrets Manager, GCP Secret Manager, HashiCorp Vault. Rotation, audit, access control. 4) Kubernetes Secrets — base64 encoded (не зашифровані за замовчуванням!). Sealed Secrets або external-secrets для production. Правила: ніколи не логувати secrets, ніколи в git, мінімальний доступ, rotation policy." },
            { level: "senior", q: "Поясни Kubernetes: pod, deployment, service, ingress.", a: "Pod — найменша deployable unit. Один або кілька контейнерів з shared network/storage. Зазвичай один container per pod. Ephemeral — може бути killed/recreated. Deployment — декларативний опис desired state: кількість replicas, image version, update strategy. Керує ReplicaSet, який керує Pods. Rolling update: поступова заміна pods. Rollback: kubectl rollout undo. Service — стабільний мережевий endpoint для групи pods. Types: ClusterIP (internal), NodePort (external port on node), LoadBalancer (cloud LB). Service discovery через DNS: service-name.namespace.svc.cluster.local. Ingress — HTTP routing rules для external traffic. URL-based routing: /api → api-service, /web → web-service. TLS termination. Ingress controllers: nginx, traefik, ALB." },
            { level: "senior", q: "Що таке horizontal vs vertical scaling? Коли що застосовується?", a: "Vertical scaling (scale up) — збільшення ресурсів одного сервера (CPU, RAM, disk). Простіше, але має фізичну межу. Downtime при upgrade. Один point of failure. Horizontal scaling (scale out) — додавання більше серверів/instances. Потребує: stateless application, load balancer, shared session store (Redis), distributed cache. Складніше, але необмежене масштабування, fault tolerant. Коли vertical: БД (простіше ніж sharding), legacy додатки, маленькі проєкти. Коли horizontal: web servers (stateless), microservices, high availability потреба. Kubernetes HPA (Horizontal Pod Autoscaler) — автоматичний scaling по CPU/memory/custom metrics. Бази даних: vertical для write, horizontal для read (replicas). Кеш: horizontal (Redis Cluster)." },
            { level: "senior", q: "Як налаштувати monitoring та alerting для production Node.js додатку?", a: "Metrics (Prometheus + Grafana): 1) System: CPU, memory, disk, network. 2) Application: request rate, response time (p50, p95, p99), error rate, active connections. 3) Business: orders/min, signups, revenue. prom-client (npm) — Prometheus metrics для Node.js. RED method: Rate, Errors, Duration. Logging (ELK Stack або Loki): structured logging (pino/winston), JSON format, correlation ID, log levels. Centralized: Elasticsearch + Kibana або Grafana Loki. Tracing (Jaeger/Zipkin): distributed tracing з OpenTelemetry. Trace ID через всі сервіси. Alerting: Grafana alerts або PagerDuty. SLI/SLO based: error rate > 1%, p99 > 2s, availability < 99.9%. Health checks: /health endpoint з readiness/liveness. Uptime monitoring: Better Uptime, Pingdom." },
            { level: "senior", q: "Поясни blue-green deployment та canary releases.", a: "Blue-Green deployment: два ідентичних production середовища. Blue — поточна версія (live). Green — нова версія. Процес: deploy на Green → тестування → switch traffic (DNS/LB) → Green стає live, Blue — backup. Rollback — миттєвий switch назад. Недоліки: подвійна інфраструктура, database migrations складні. Canary release: нова версія розгортається на маленький % трафіку (5-10%). Моніторинг metrics. Поступове збільшення: 5% → 25% → 50% → 100%. При проблемах — rollback тільки canary. Переваги: менший ризик, реальні user metrics. Інструменти: Kubernetes (Istio, Argo Rollouts), AWS CodeDeploy, Vercel (automatic). Feature flags — ще один підхід: toggle feature для % users без нового deploy (LaunchDarkly, Unleash)." },
            { level: "senior", q: "Що таке CDN? Як він покращує перформанс фронтенду?", a: "CDN (Content Delivery Network) — розподілена мережа серверів (edge nodes/PoPs) по всьому світу. Кешує та доставляє контент з найближчого сервера до користувача. Покращення: 1) Latency — фізично ближче до користувача (50ms замість 200ms). 2) Bandwidth — розвантажує origin server. 3) Availability — redundancy, DDoS protection. 4) HTTP/2-3 — оптимізовані протоколи на edge. Що кешувати: static assets (JS, CSS, images, fonts) — long cache (immutable, content hash у назві). HTML — short cache або stale-while-revalidate. API — залежить від даних. Провайдери: Cloudflare (free tier), AWS CloudFront, Vercel Edge Network, Fastly. Edge computing: Cloudflare Workers, Vercel Edge Functions — логіка на edge (auth, A/B testing, personalization). Cache invalidation — purge при deploy." },
        ],
    },
};

const levelColors: Record<Level, { bg: string; text: string; label: string }> = {
    junior: { bg: "#1a3a2a", text: "#4ade80", label: "Junior" },
    middle: { bg: "#1a2a3a", text: "#60a5fa", label: "Middle" },
    senior: { bg: "#3a1a2a", text: "#f472b6", label: "Senior" },
};

export default function App() {
    const [activeCategory, setActiveCategory] = useState<string | null>(null);
    const [filter, setFilter] = useState("all");
    const [search, setSearch] = useState("");
    const [checked, setChecked] = useState<Record<string, boolean>>({});
    const [view, setView] = useState<"categories" | "all">("categories");
    const [expanded, setExpanded] = useState<string | null>(null);

    const toggleCheck = (id: string) => {
        setChecked((prev) => ({ ...prev, [id]: !prev[id] }));
    };

    const allQuestions = useMemo(() => {
        const result: Array<Question & { cat: string; color: string; icon: string; id: string }> = [];
        Object.entries(data).forEach(([cat, { questions, color, icon }]) => {
            questions.forEach((q, i) => {
                result.push({ ...q, cat, color, icon, id: `${cat}-${i}` });
            });
        });
        return result;
    }, []);

    const totalStats = useMemo(() => {
        const total = allQuestions.length;
        const done = Object.values(checked).filter(Boolean).length;
        return { total, done, pct: Math.round((done / total) * 100) };
    }, [allQuestions, checked]);

    const filteredQuestions = useMemo(() => {
        return allQuestions.filter((q) => {
            const matchLevel = filter === "all" || q.level === filter;
            const matchSearch = q.q.toLowerCase().includes(search.toLowerCase()) || q.cat.toLowerCase().includes(search.toLowerCase());
            const matchCat = !activeCategory || q.cat === activeCategory;
            return matchLevel && matchSearch && matchCat;
        });
    }, [allQuestions, filter, search, activeCategory]);

    const categoryStats = useMemo(() => {
        const stats: Record<string, { total: number; done: number }> = {};
        allQuestions.forEach((q) => {
            if (!stats[q.cat]) stats[q.cat] = { total: 0, done: 0 };
            stats[q.cat].total++;
            if (checked[q.id]) stats[q.cat].done++;
        });
        return stats;
    }, [allQuestions, checked]);

    return (
        <div style={{ minHeight: "100vh", background: "#0d1117", color: "#e6edf3", fontFamily: "'Segoe UI', system-ui, sans-serif" }}>
            {/* Header */}
            <div style={{ background: "linear-gradient(135deg, #161b22 0%, #0d1117 100%)", borderBottom: "1px solid #30363d", padding: "24px 32px", position: "sticky", top: 0, zIndex: 100 }}>
                <div style={{ maxWidth: 1200, margin: "0 auto" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 16 }}>
                        <div>
                            <h1 style={{ margin: 0, fontSize: 24, fontWeight: 700, background: "linear-gradient(90deg, #58a6ff, #f472b6)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>
                                🎯 Senior Frontend Prep
                            </h1>
                            <p style={{ margin: "4px 0 0", color: "#8b949e", fontSize: 13 }}>
                                {totalStats.total} питань · React, Next.js, TS, Node.js, NestJS, MongoDB
                            </p>
                        </div>
                        <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
                            <div style={{ textAlign: "right" }}>
                                <div style={{ fontSize: 22, fontWeight: 700, color: "#58a6ff" }}>{totalStats.pct}%</div>
                                <div style={{ fontSize: 11, color: "#8b949e" }}>{totalStats.done}/{totalStats.total}</div>
                            </div>
                            <div style={{ width: 60, height: 60, position: "relative" }}>
                                <svg viewBox="0 0 36 36" style={{ width: 60, height: 60, transform: "rotate(-90deg)" }}>
                                    <circle cx="18" cy="18" r="16" fill="none" stroke="#30363d" strokeWidth="3" />
                                    <circle cx="18" cy="18" r="16" fill="none" stroke="#58a6ff" strokeWidth="3"
                                            strokeDasharray={`${totalStats.pct} 100`} strokeLinecap="round" />
                                </svg>
                            </div>
                        </div>
                    </div>

                    {/* Controls */}
                    <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
                        <input
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder="🔍 Пошук питань..."
                            style={{ flex: 1, minWidth: 200, background: "#161b22", border: "1px solid #30363d", borderRadius: 8, padding: "8px 14px", color: "#e6edf3", fontSize: 14, outline: "none" }}
                        />
                        <div style={{ display: "flex", gap: 6 }}>
                            {(["all", "junior", "middle", "senior"] as const).map((l) => (
                                <button key={l} onClick={() => setFilter(l)}
                                        style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid", cursor: "pointer", fontSize: 13, fontWeight: 600, transition: "all 0.2s",
                                            background: filter === l ? (l === "all" ? "#58a6ff" : levelColors[l].text) : "transparent",
                                            borderColor: filter === l ? "transparent" : "#30363d",
                                            color: filter === l ? "#000" : "#8b949e" }}>
                                    {l === "all" ? "Всі" : levelColors[l].label}
                                </button>
                            ))}
                        </div>
                        <div style={{ display: "flex", gap: 6 }}>
                            <button onClick={() => { setView("categories"); setActiveCategory(null); }}
                                    style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid", cursor: "pointer", fontSize: 13,
                                        background: view === "categories" && !activeCategory ? "#21262d" : "transparent",
                                        borderColor: view === "categories" && !activeCategory ? "#58a6ff" : "#30363d", color: "#e6edf3" }}>
                                📂 Категорії
                            </button>
                            <button onClick={() => { setView("all"); setActiveCategory(null); }}
                                    style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid", cursor: "pointer", fontSize: 13,
                                        background: view === "all" ? "#21262d" : "transparent",
                                        borderColor: view === "all" ? "#58a6ff" : "#30363d", color: "#e6edf3" }}>
                                📋 Всі питання
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            {/* Content */}
            <div style={{ maxWidth: 1200, margin: "0 auto", padding: "32px 32px" }}>

                {/* Categories grid */}
                {view === "categories" && !activeCategory && (
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 16 }}>
                        {Object.entries(data).map(([cat, { icon, color }]) => {
                            const stats = categoryStats[cat] || { total: 0, done: 0 };
                            const pct = stats.total > 0 ? Math.round((stats.done / stats.total) * 100) : 0;
                            return (
                                <div key={cat} onClick={() => setActiveCategory(cat)} style={{ background: "#161b22", border: "1px solid #30363d", borderRadius: 12, padding: 20, cursor: "pointer", transition: "all 0.2s", position: "relative", overflow: "hidden" }}
                                     onMouseEnter={(e) => { e.currentTarget.style.borderColor = color; e.currentTarget.style.transform = "translateY(-2px)"; }}
                                     onMouseLeave={(e) => { e.currentTarget.style.borderColor = "#30363d"; e.currentTarget.style.transform = "none"; }}>
                                    <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 3, background: color, opacity: 0.8 }} />
                                    <div style={{ fontSize: 28, marginBottom: 8 }}>{icon}</div>
                                    <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>{cat}</div>
                                    <div style={{ color: "#8b949e", fontSize: 13, marginBottom: 12 }}>{stats.total} питань</div>
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: 12 }}>
                                        <div style={{ height: 4, flex: 1, background: "#21262d", borderRadius: 4, marginRight: 10 }}>
                                            <div style={{ height: "100%", width: `${pct}%`, background: color, borderRadius: 4, transition: "width 0.3s" }} />
                                        </div>
                                        <span style={{ color, fontWeight: 700 }}>{pct}%</span>
                                    </div>
                                    <div style={{ marginTop: 10, display: "flex", gap: 6 }}>
                                        {(["junior", "middle", "senior"] as const).map((l) => {
                                            const cnt = data[cat].questions.filter((q) => q.level === l).length;
                                            return cnt > 0 ? (
                                                <span key={l} style={{ fontSize: 11, padding: "2px 8px", borderRadius: 12, background: levelColors[l].bg, color: levelColors[l].text }}>
                          {levelColors[l].label}: {cnt}
                        </span>
                                            ) : null;
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}

                {/* Questions list */}
                {(view === "all" || activeCategory) && (
                    <div>
                        {activeCategory && (
                            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 24 }}>
                                <button onClick={() => setActiveCategory(null)}
                                        style={{ background: "transparent", border: "1px solid #30363d", borderRadius: 8, padding: "6px 14px", color: "#8b949e", cursor: "pointer", fontSize: 13 }}>
                                    ← Назад
                                </button>
                                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 700 }}>
                                    {data[activeCategory].icon} {activeCategory}
                                </h2>
                            </div>
                        )}
                        <div style={{ fontSize: 13, color: "#8b949e", marginBottom: 16 }}>
                            {filteredQuestions.length} питань
                        </div>
                        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                            {filteredQuestions.map((q) => {
                                const lc = levelColors[q.level];
                                const isDone = checked[q.id];
                                const isExpanded = expanded === q.id;
                                return (
                                    <div key={q.id}
                                         style={{ background: isDone ? "#0f1e14" : "#161b22",
                                             border: `1px solid ${isDone ? "#2ea043" : isExpanded ? q.color : "#30363d"}`, borderRadius: 10,
                                             transition: "all 0.2s", opacity: isDone ? 0.7 : 1 }}
                                         onMouseEnter={(e) => { if (!isDone && !isExpanded) e.currentTarget.style.borderColor = q.color; }}
                                         onMouseLeave={(e) => { if (!isDone && !isExpanded) e.currentTarget.style.borderColor = "#30363d"; }}>
                                        <div style={{ display: "flex", alignItems: "flex-start", gap: 14, padding: "14px 18px", cursor: "pointer" }}
                                             onClick={() => toggleCheck(q.id)}>
                                            <div style={{ width: 20, height: 20, borderRadius: 6, border: `2px solid ${isDone ? "#2ea043" : "#30363d"}`,
                                                background: isDone ? "#2ea043" : "transparent", display: "flex", alignItems: "center", justifyContent: "center",
                                                flexShrink: 0, marginTop: 2, transition: "all 0.2s" }}>
                                                {isDone && <span style={{ color: "#fff", fontSize: 12, lineHeight: 1 }}>✓</span>}
                                            </div>
                                            <div style={{ flex: 1 }}>
                                                <div style={{ display: "flex", gap: 8, marginBottom: 6, flexWrap: "wrap" }}>
                                                    <span style={{ fontSize: 11, padding: "2px 8px", borderRadius: 12, background: lc.bg, color: lc.text, fontWeight: 600 }}>
                                                        {lc.label}
                                                    </span>
                                                    {!activeCategory && (
                                                        <span style={{ fontSize: 11, padding: "2px 8px", borderRadius: 12, background: "#21262d", color: q.color }}>
                                                            {q.icon} {q.cat}
                                                        </span>
                                                    )}
                                                </div>
                                                <div style={{ fontSize: 15, lineHeight: 1.5, color: isDone ? "#8b949e" : "#e6edf3", textDecoration: isDone ? "line-through" : "none" }}>
                                                    {q.q}
                                                </div>
                                            </div>
                                            {q.a && (
                                                <button onClick={(e) => { e.stopPropagation(); setExpanded(isExpanded ? null : q.id); }}
                                                        style={{ background: "transparent", border: "1px solid #30363d", borderRadius: 6, padding: "4px 10px",
                                                            color: isExpanded ? q.color : "#8b949e", cursor: "pointer", fontSize: 12, flexShrink: 0, marginTop: 2,
                                                            transition: "all 0.2s" }}>
                                                    {isExpanded ? "▲" : "▼"}
                                                </button>
                                            )}
                                        </div>
                                        {isExpanded && q.a && (
                                            <div style={{ padding: "0 18px 16px 52px", fontSize: 14, lineHeight: 1.7, color: "#b0bac5",
                                                borderTop: "1px solid #21262d", marginTop: 0, paddingTop: 14 }}>
                                                {q.a}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}
